iables\" as *;\n@use \"typography\" as *;\n@use \"common\" as *;\n@use \"buttons\" as *;\n@use \"templates/navigation\" as *;\n@use \"templates/main\" as *;\n","@import url(https://fonts.googleapis.com/css?family=Montserrat:300,400,400i,500,500i,600,600i,700,700i,800|Open+Sans:400,400i,600,600i,700,700i,800&display=swap);\n\n/* Typography\n================================================== */\n\nbody {\n  background: #fff;\n  color: #555;\n}\n\nbody,\np {\n  font-family: \"Open Sans\", sans-serif;\n  text-rendering: optimizeLegibility;\n  -webkit-font-smoothing: antialiased !important;\n  line-height: 26px;\n  font-size: 15px;\n}\n\nh1,\nh2,\nh3,\nh4,\nh5,\nh6 {\n  color: #212121;\n  font-weight: 700;\n  font-family: \"Montserrat\", sans-serif;\n  text-rendering: optimizeLegibility;\n  -webkit-font-smoothing: antialiased !important;\n}\n\nh1 {\n  font-size: 36px;\n  line-height: 48px;\n}\n\nh2 {\n  font-size: 28px;\n  line-height: 36px;\n  text-transform: uppercase;\n  letter-spacing: -1px;\n}\n\nh3 {\n  font-size: 24px;\n  margin-bottom: 20px;\n  text-transform: uppercase;\n  letter-spacing: -0.5px;\n}\n\nh4 {\n  font-size: 18px;\n  line-height: 28px;\n  text-transform: uppercase;\n  letter-spacing: -0.2px;\n}\n\nh5 {\n  font-size: 14px;\n  line-height: 24px;\n}\n\n.alert .icon {\n  margin-right: 15px;\n}\n","/*!\nTHEME: Constra - Construction Html5 Template\nVERSION: 1.0.0\nAUTHOR: Themefisher\n\nHOMEPAGE: https://themefisher.com/products/constra-construction-template/\nDEMO: https://demo.themefisher.com/constra/\nGITHUB: https://github.com/themefisher/Constra-Bootstrap-Construction-Template\n\nWEBSITE: https://themefisher.com\nTWITTER: https://twitter.com/themefisher\nFACEBOOK: https://www.facebook.com/themefisher\n*/\n@import url(https://fonts.googleapis.com/css?family=Montserrat:300,400,400i,500,500i,600,600i,700,700i,800|Open+Sans:400,400i,600,600i,700,700i,800&display=swap);\n/* Typography\n================================================== */\nbody {\n  background: #fff;\n  color: #555;\n}\n\nbody,\np {\n  font-family: \"Open Sans\", sans-serif;\n  text-rendering: optimizeLegibility;\n  -webkit-font-smoothing: antialiased !important;\n  line-height: 26px;\n  font-size: 15px;\n}\n\nh1,\nh2,\nh3,\nh4,\nh5,\nh6 {\n  color: #212121;\n  font-weight: 700;\n  font-family: \"Montserrat\", sans-serif;\n  text-rendering: optimizeLegibility;\n  -webkit-font-smoothing: antialiased !important;\n}\n\nh1 {\n  font-size: 36px;\n  line-height: 48px;\n}\n\nh2 {\n  font-size: 28px;\n  line-height: 36px;\n  text-transform: uppercase;\n  letter-spacing: -1px;\n}\n\nh3 {\n  font-size: 24px;\n  margin-bottom: 20px;\n  text-transform: uppercase;\n  letter-spacing: -0.5px;\n}\n\nh4 {\n  font-size: 18px;\n  line-height: 28px;\n  text-transform: uppercase;\n  letter-spacing: -0.2px;\n}\n\nh5 {\n  font-size: 14px;\n  line-height: 24px;\n}\n\n.alert .icon {\n  margin-right: 15px;\n}\n\n/* Global styles\n================================================== */\nhtml {\n  overflow-x: hidden !important;\n  width: 100%;\n  height: 100%;\n  position: relative;\n  -webkit-font-smoothing: antialiased;\n  text-rendering: optimizeLegibility;\n}\n\nbody {\n  border: 0;\n  margin: 0;\n  padding: 0;\n}\n\n.body-inner {\n  position: relative;\n  overflow: hidden;\n}\n\n.preload {\n  position: fixed;\n  background: #fff url(../images/preload.gif) center center no-repeat;\n  left: 0px;\n  top: 0px;\n  width: 100%;\n  height: 100%;\n  z-index: 99999;\n}\n\na:link,\na:visited {\n  text-decoration: none;\n}\n\na {\n  color: inherit;\n  transition: 0.2s ease;\n}\n\na:hover {\n  text-decoration: none;\n  color: #000;\n}\n\na.read-more {\n  color: #ffb600;\n  font-weight: 700;\n  text-transform: uppercase;\n}\n\na.read-more:hover {\n  color: #222;\n}\n\nsection,\n.section-padding {\n  padding: 70px 0;\n  position: relative;\n}\n\n.no-padding {\n  padding: 0;\n}\n\n.gap-60 {\n  clear: both;\n  height: 60px;\n}\n\n.gap-40 {\n  clear: both;\n  height: 40px;\n}\n\n.gap-30 {\