,\nul.navbar-nav > li.active > a {\n  color: #ffb600;\n  position: relative;\n}\n\nul.navbar-nav > li {\n  padding: 0 13px;\n  position: relative;\n}\n@media (min-width: 992px) {\n  ul.navbar-nav > li {\n    padding: 0 9px;\n  }\n  ul.navbar-nav > li .nav-link {\n    font-size: 12px;\n  }\n}\n\n.header-two .navbar-nav > .header-get-a-quote {\n  top: -4px;\n}\n\n@media (min-width: 992px) {\n  .header-two ul.navbar-nav > li {\n    padding: 0;\n    width: 100%;\n  }\n}\n\nul.navbar-nav > li:last-child {\n  padding-right: 0;\n}\n\nul.navbar-nav > li:last-child:after {\n  background: none;\n}\n\nul.navbar-nav > li > a:hover,\nul.navbar-nav > li > a:focus {\n  background: none;\n}\n\nul.navbar-nav > li > a i {\n  font-weight: 700;\n}\n\n@media (min-width: 992px) {\n  ul.navbar-nav > li > a i {\n    float: right;\n    background: #222;\n    padding: 6px 10px;\n    margin-top: 7px;\n  }\n  .header-two ul.navbar-nav > li > a i {\n    color: #fff;\n  }\n  .header-two ul.navbar-nav > li.active > a i,\n  .header-two ul.navbar-nav > li > a.active i {\n    color: #ffb600;\n  }\n}\nul.navbar-nav > li > a:after,\nul.navbar-nav > li > a:after {\n  display: none;\n}\n\nul.navbar-nav > li > a {\n  font-family: \"Montserrat\", sans-serif;\n  color: #fff !important;\n  text-rendering: optimizeLegibility;\n  font-weight: 700 !important;\n  text-transform: uppercase;\n  letter-spacing: -0.2px;\n  font-size: 14px;\n  margin: 0;\n  line-height: 40px;\n  padding: 30px 0;\n  -webkit-transition: 350ms;\n  -moz-transition: 350ms;\n  -o-transition: 350ms;\n  transition: 350ms;\n}\n\n.navbar-light ul.navbar-nav > li > a {\n  color: #000 !important;\n  font-size: 13px;\n}\n\n/* Dropdown */\n.dropdown-submenu {\n  position: relative;\n}\n\n.dropdown-submenu > .dropdown-menu {\n  top: 0;\n  left: 100%;\n  margin-top: -2px;\n  border-radius: 0;\n}\n\n.dropdown-submenu > a:after {\n  display: block;\n  content: \"\\f105\";\n  font-family: \"Font Awesome 5 Free\";\n  float: right;\n  margin-top: 0;\n  margin-right: -5px;\n  border: 0;\n}\n\n.dropdown-submenu:hover > a:after {\n  border-left-color: #fff;\n}\n\n.dropdown-menu {\n  text-align: left;\n  background: #fff;\n  z-index: 100;\n  min-width: 200px;\n  border-radius: 0;\n  border: 0;\n  border-top: 2px solid #ffb600;\n  padding: 0 20px;\n  margin: 0;\n  box-shadow: 0 6px 12px rgba(0, 0, 0, 0.175);\n}\n@media (min-width: 992px) {\n  .dropdown-menu {\n    box-shadow: 0 6px 12px rgba(0, 0, 0, 0.05);\n  }\n}\n\n.dropdown-menu-large {\n  min-width: 400px;\n}\n\n.dropdown-menu-large > li > ul {\n  padding: 0;\n  margin: 0;\n  list-style: none;\n}\n\n.dropdown-menu-large > li > ul > li > a {\n  padding-left: 0;\n}\n\n.dropdown-menu-large > li > ul > li.active > a {\n  color: #ffb600 !important;\n}\n\n.navbar-nav > li > .dropdown-menu a {\n  background: none;\n}\n\n.dropdown-menu li a {\n  font-family: \"Montserrat\", sans-serif;\n  display: block;\n  font-size: 12px;\n  text-transform: uppercase;\n  font-weight: 700;\n  line-height: normal;\n  text-decoration: none;\n  padding: 15px 0;\n  letter-spacing: 0.3px;\n  border-bottom: 1px solid #e5e5e5;\n  color: #333333;\n}\n@media (min-width: 992px) {\n  .dropdown-menu li a {\n    padding: 12px 0;\n  }\n}\n\n.dropdown-menu li:last-child > a {\n  border-bottom: 0;\n}\n\n.dropdown-menu li a:hover,\n.dropdown-menu li a:focus {\n  color: #ffb600;\n}\n\n@media (min-width: 991px) {\n  ul.nav li.dropdown:hover ul.dropdown-menu {\n    display: block;\n  }\n}\n@media (min-width: 991px) {\n  ul.nav li.dropdown ul.dropdown-menu li.dropdown-submenu .dropdown-menu {\n    left: 100%;\n    top: 0;\n    display: none;\n  }\n  ul.nav li.dropdown ul.dropdown-menu li.dropdown-submenu:hover .dropdown-menu {\n    display: block;\n  }\n}\n.dropdown-menu > .active > a,\n.dropdown-menu > .active > a:hover,\n.dropdown-menu > .active > a:focus,\n.dropdown-menu > .active > .dropdown-menu > .active > a {\n  background: none;\n  color: #ffb600;\n}\n\n/*-- Nav Search start --*/\n.site-navigation .container,\n.search-area {\n  position: relative;\n}\n\n.search-area {\n  min-height: 70px;\n  padding-right: 0;\n}\n\n.nav-search {\n  position: absolute;\n  cursor: pointer;\n  top: 22px;\n  right: 18px;\n  color: #999;\n}\n@media (min-width: 992px) {\n  .nav-search {\n    top: 17px;\n  }\n}\n\n.search-block {\n  background-color: rgba(0, 0, 0, 0.65);\n  box-shadow: 0 2px 5px rgba(0, 0, 0, 0.1);\n  display: none;\n  padding: 10px;\n  position: absolute;\n  right: 15px;\n  top: 100%;\n  width: 300px;\n  z-index: 10;\n  margin-top: 0;\n}\n@media (min-width: 992px) {\n  .search-block {\n    top: 58px;\n  }\n}\n\n.search-block .form-control {\n  background-color: #222;\n  border: none;\n  color: #fff;\n  width: 100%;\n  height: 40px;\n  padding: 0 12px;\n}\n\n.search-block .search-close {\n  color: #999;\n  position: absolute;\n  top: -53px;\n  right: -4px;\n  font-size: 32px;\n  cursor: pointer;\n  background: #23282d;\n  padding: 5px;\n}\n@media (min-width: 992px) {\n  .search-block .search-close {\n    top: -46px;\n  }\n}\n\n.search-area .nav-search {\n  top: 23px;\n}\n\n.search-area .search-block .search-close {\n  top: -50px;\n}\n\n.search-area .search-block {\n  right: 0;\n}\n\n/* Get a quote */\n.header-get-a-quote .btn-primary {\n  padding: 12px 25px !important;\n  font-size: 13px;\n  border-radius: 3px;\n  line-height: normal;\n  text-transform: capitalize;\n  color: #fff;\n  margin-top: 5px;\n}\n@media (min-width: 992px) {\n  .header-get-a-quote .btn-primary {\n    padding: 12px !important;\n  }\n}\n@media (min-width: 992px) {\n  .header-get-a-quote .btn-primary {\n    padding: 12px 30px !important;\n  }\n}\n\n.header-get-a-quote .btn-primary:hover {\n  background: #272d33;\n  color: #ffb600 !important;\n}\n\nul.navbar-nav > li.header-get-a-quote:hover > a:after {\n  position: relative;\n  content: no-close-quote;\n}\n\n/* Table of Content\n==================================================\n1.    Slider\n2.    Call to action\n3.    Features\n4.    Facts\n5.    Services\n6.   Project area\n7.   Content area\n8.   Testimonial\n9.   Subscribe area\n10.   News section\n11.   Footer\n12.   Sub Pages\n13.   Contact Us\n14.   News Listing\n15.   News Single\n16.   Sidebar\n17.   Error page\n*/\n/* Slider\n================================================== */\n/*-- Main slide --*/\n.banner-carousel .banner-carousel-item {\n  height: 700px;\n  color: #fff;\n  background-position: 50% 50%;\n  background-size: cover;\n  height: 450px;\n}\n@media (min-width: 992px) {\n  .banner-carousel .banner-carousel-item {\n    height: 550px;\n  }\n}\n\n.slider-content {\n  position: relative;\n  height: 100%;\n  width: 100%;\n}\n\n.slide-title-box {\n  font-size: 16px;\n  line-height: 39px;\n  background: #ffb600;\n  color: #fff;\n  display: inline-block;\n  padding: 0 15px;\n  margin: 0 0 10px;\n}\n\n.slide-title {\n  font-size: 30px;\n  line-height: 36px;\n  font-weight: 300;\n  color: #fff;\n  margin: 20px 0 10px;\n}\n@media (min-width: 992px) {\n  .slide-title {\n    font-size: 22px;\n  }\n}\n@media (max-width: 992px) {\n  .slide-title {\n    font-size: 16px;\n  }\n}\n\n.slide-sub-title {\n  font-style: normal;\n  font-size: 60px;\n  line-height: 58px;\n  margin: 20px 0;\n  color: #fff;\n  font-weight: 900;\n  text-transform: uppercase;\n  letter-spacing: -1px;\n}\n@media (min-width: 992px) {\n  .slide-sub-title {\n    font-size: 46px;\n  }\n}\n@media (max-width: 992px) {\n  .slide-sub-title {\n    font-size: 30px;\n    line-height: 30px;\n  }\n}\n\n.slider-text {\n  display: table;\n  vertical-align: bottom;\n  color: #fff;\n  padding-left: 40%;\n  width: 100%;\n  padding-bottom: 0;\n  padding-top: 20px;\n}\n\n.slider-text .slide-head {\n  font-size: 36px;\n  color: #0052a5;\n  position: relative;\n}\n\n.slider-img {\n  display: block;\n  position: absolute;\n  top: -80px;\n  left: 20%;\n  width: 314px;\n  max-height: 100%;\n}\n\n.slider-img img {\n  display: block;\n  position: relative;\n  max-height: 100%;\n  width: auto;\n}\n\n.slider.btn {\n  margin: 15px 5px 0;\n  border: 2px solid transparent;\n}\n@media (max-width: 992px) {\n  .slider.btn {\n    font-size: 12px;\n  }\n}\n\n.slider.border {\n  background: none;\n  border: 2px solid #ffb600 !important;\n}\n\n.slider.border:hover {\n  background: #ffb600;\n  border: 2px solid transparent;\n}\n\n/* Carousel control */\n.banner-carousel .carousel-control {\n  position: absolute;\n  top: 50%;\n  z-index: 5;\n  display: inline-block;\n  transform: translateY(-50%);\n  background-color: transparent;\n  opacity: 0;\n  filter: alpha(opacity=0);\n  text-shadow: none;\n  transition: all 0.25s ease;\n  padding: 0;\n  outline: 0;\n  border: 0;\n}\n@media (max-width: 992px) {\n  .banner-carousel .carousel-control {\n    display: none !important;\n  }\n}\n\n.banner-carousel .slick-dots {\n  opacity: 0;\n  filter: alpha(opacity=0);\n  bottom: 60px;\n}\n\n.slick-dots li button::before {\n  font-size: 12px;\n}\n.slick-dots li button:hover:before,\n.slick-dots .slick-dots li button:focus:before,\n.slick-dots li.slick-active button:before {\n  opacity: 1;\n  color: #ffb600;\n}\n\n.slick-slide {\n  outline: 0;\n}\n\n.banner-carousel:hover .carousel-control,\n.banner-carousel:hover .carousel-control,\n.banner-carousel:hover .slick-dots {\n  opacity: 1;\n  filter: alpha(opacity=100);\n}\n\n.banner-carousel .carousel-control.left {\n  left: 20px;\n}\n\n.banner-carousel .carousel-control.right {\n  right: 20px;\n}\n\n.banner-carousel .carousel-control i {\n  background: rgba(0, 0, 0, 0.3);\n  color: #fff;\n  line-height: 58px;\n  width: 60px;\n  height: 60px;\n  font-size: 22px;\n  border-radius: 0;\n  transition: all 500ms ease;\n}\n\n.banner-carousel .carousel-control i:hover {\n  background: #ffb600;\n  color: #fff;\n}\n\n/*-- Animation */\n.banner-carousel [data-animation-in] {\n  opacity: 0;\n}\n\n/* slick Box slider */\n.box-slider-content {\n  top: 50%;\n  padding: 0;\n  position: absolute;\n  width: 100%;\n  transform: translateY(-50%);\n}\n@media (max-width: 992px) {\n  .box-slider-content {\n    top: auto;\n    transform: translateY(0);\n    left: 20px;\n    bottom: 20px;\n    width: calc(100% - 40px);\n  }\n}\n\n.box-slider-text {\n  background: #111;\n  background: rgba(0, 0, 0, 0.65);\n  display: inline-block;\n  padding: 20px 30px;\n  max-width: 650px;\n}\n\n.box-slide-title {\n  font-size: 18px;\n  font-weight: 300;\n  margin: 0;\n  color: #fff;\n}\n@media (max-width: 992px) {\n  .box-slide-title {\n    font-size: 16px;\n  }\n}\n\n.box-slide-sub-title {\n  font-size: 36px;\n  margin: 8px 0 10px;\n  color: #fff;\n}\n@media (max-width: 992px) {\n  .box-slide-sub-title {\n    font-size: 26px;\n  }\n}\n\n.box-slide-description {\n  color: #fff;\n}\n@media (max-width: 992px) {\n  .box-slide-description {\n    font-size: 15px;\n  }\n}\n\n.box-slider-text .btn {\n  padding: 10px 20px;\n}\n\n.box-slide.owl-theme .owl-controls {\n  margin: -20px;\n}\n\n/* Call to action\n================================================== */\n.call-to-action {\n  background-color: #272d33;\n  padding: 30px;\n}\n\n.call-to-action-title {\n  color: #fff;\n  margin: 0;\n  padding: 25px 0;\n  line-height: normal;\n  font-size: 22px;\n  text-transform: capitalize;\n}\n\n/* Action style box */\n.call-to-action-box {\n  margin-top: -50px;\n}\n\n.call-to-action-box .action-style-box {\n  background: #ffb600;\n  padding: 30px;\n}\n\n.action-title {\n  color: #fff;\n  margin: 0;\n  line-height: 36px;\n  font-size: 18px;\n  text-transform: uppercase;\n}\n\n/* Intro\n================================================== */\n/* Intro */\n.ts-intro {\n  padding-right: 20px;\n}\n\n.into-title {\n  font-weight: 300;\n  text-transform: uppercase;\n  font-size: 18px;\n  line-height: normal;\n  margin: 0;\n}\n\n.into-sub-title {\n  font-weight: 900;\n  text-transform: uppercase;\n  font-size: 32px;\n  line-height: normal;\n  margin: 10px 0;\n}\n\n/*-- Featured Tab --*/\n.featured-tab {\n  padding-left: 15px;\n}\n\n.featured-tab .nav-tabs {\n  border: 0;\n}\n\n.featured-tab .nav-tabs > li > a {\n  font-family: \"Roboto Slab\", serif;\n  background: #272d33;\n  color: #fff;\n  text-shadow: none;\n  font-weight: 700;\n  border-radius: 0;\n  text-transform: uppercase;\n  line-height: 50px;\n  margin: 0 1px 20px;\n  padding: 0 20px;\n  border: 0 !important;\n  transition: all 300ms ease;\n}\n\n.featured-tab .tab-content {\n  border-top: 0;\n  padding: 0;\n  overflow: hidden;\n}\n\n.featured-tab .nav.nav-tabs {\n  margin-bottom: 10px;\n}\n\n.featured-tab .nav-tabs > li.active > a {\n  color: #fff;\n  background: #ffb600;\n  position: relative;\n}\n\n.featured-tab .nav-tabs > li.active > a:after {\n  position: absolute;\n  content: \" \";\n  width: auto;\n  height: auto;\n  bottom: -20px;\n  left: 50%;\n  border-width: 10px;\n  border-style: solid;\n  border-color: #ffb600 rgba(0, 0, 0, 0) rgba(0, 0, 0, 0) rgba(0, 0, 0, 0);\n  transform: translateX(-50%);\n}\n\n.featured-tab .lead {\n  font-size: 18px;\n  line-height: 28px;\n  color: #303030;\n  font-weight: 400;\n}\n\n.featured-tab .tab-pane img.pull-left {\n  margin: 0 30px 10px 0;\n}\n\n.featured-tab .tab-pane img.pull-right {\n  margin: 0 0 0 30px;\n}\n\n.featured-tab .tab-icon i {\n  font-size: 230px;\n}\n\n.tab-image-content {\n  padding-left: 0;\n}\n\n.featured-tab .border-title.border-left {\n  display: inline-block;\n  margin-bottom: 25px;\n  font-size: 20px;\n}\n\n/* Tab services */\n.featured-tab.tab-services .nav-tabs > li > a {\n  font-size: 14px;\n  padding: 0 21px;\n  text-transform: capitalize;\n}\n\n.featured-tab.tab-services .nav.nav-tabs {\n  margin-bottom: 20px;\n}\n\n/* Facts\n================================================== */\n.facts-wrapper {\n  text-align: center;\n}\n\n.facts-wrapper .ts-facts {\n  color: #fff;\n}\n\n.ts-facts .ts-facts-icon i {\n  font-size: 42px;\n  color: #ffb600;\n}\n\n.ts-facts .ts-facts-content .ts-facts-num {\n  color: #fff;\n  font-size: 44px;\n  margin: 30px 0 20px;\n}\n\n.ts-facts .ts-facts-content .ts-facts-title {\n  font-size: 16px;\n  color: #ffb600;\n  margin: 0;\n}\n\n/* Services\n================================================== */\n/* Service box */\n.ts-service-box .ts-service-icon i {\n  font-size: 36px;\n  float: left;\n  color: #ffb600;\n}\n\n.ts-service-box .ts-service-box-content {\n  margin-left: 62px;\n  margin-bottom: 30px;\n}\n\n.tab-content .ts-service-box .ts-service-box-content {\n  margin-left: 90px;\n}\n\n.ts-service-box .ts-service-box-content h3 {\n  font-size: 16px;\n  margin-bottom: 10px;\n  line-height: 28px;\n}\n\n.ts-service-box .ts-service-box-info {\n  margin-left: 25px;\n  margin-bottom: 40px;\n}\n\n.service-box-title {\n  font-size: 16px;\n  margin: 0 0 10px;\n}\n.service-box-title a {\n  color: #333;\n}\n.service-box-title a:hover {\n  color: #ffb600;\n}\n\n/* Service box bg */\n.ts-service-box-bg {\n  background: #252525;\n  color: #fff;\n  padding: 30px;\n}\n\n.ts-service-box-bg h4,\n.ts-service-box-bg h3 {\n  color: #fff;\n}\n\n/* Service box \n\n.ts-service-box .ts-service-icon i {\n  font-size: 24px;\n  float: left;\n  color: #fff;\n  background: #ffb600;\n  border-radius: 100%;\n  width: 60px;\n  height: 60px;\n  line-height: 60px;\n  text-align: center;\n}\n\n.ts-service-box .ts-service-box-content {\n  margin-left: 80px;\n  margin-bottom: 30px;\n}\n\n.tab-content .ts-service-box .ts-service-box-content {\n  margin-left: 90px;\n}\n\n.ts-service-box .ts-service-box-content h3 {\n  font-size: 18px;\n  margin-bottom: 15px;\n}\n\n.ts-service-box .ts-service-box-info {\n  margin-left: 90px;\n  margin-bottom: 40px;\n}\n\n.service-box-title {\n  font-size: 18px;\n  margin: 0 0 10px;\n}\n\n.service-box-title a {\n  color: #333;\n}\n\n.service-box-title a:hover {\n  color: #ffb600;\n}\n\n.service-center-img {\n  padding: 0 20px;\n}\n*/\n/* Icon squre */\n.ts-service-icon.icon-round i {\n  font-size: 24px;\n  color: #fff;\n  background: #ffb600;\n  text-align: center;\n  border-radius: 100%;\n  width: 60px;\n  height: 60px;\n  line-height: 60px;\n  margin-bottom: 20px;\n  position: relative;\n  float: none;\n}\n\n/* Icon left */\n.ts-service-box.icon-left .ts-service-box-icon {\n  float: left;\n}\n\n.ts-service-box.icon-left .ts-service-box-icon i {\n  background: #ffb600;\n  color: #fff;\n}\n\n.ts-service-box.icon-left .ts-service-box-info {\n  margin-left: 90px;\n}\n\n.ts-service-box.icon-left .ts-service-box-info h3 {\n  margin-top: 0;\n  margin-bottom: 5px;\n}\n\n/* Service no box */\n.service-no {\n  font-size: 48px;\n  color: #dbdbdb;\n  float: left;\n  margin-top: 10px;\n}\n\n.ts-service-box-content .ts-service-box-info {\n  margin-left: 90px;\n}\n\n/* Service Image */\n.ts-service-image-wrapper {\n  margin-bottom: 30px;\n}\n\n.ts-service-icon i {\n  font-size: 28px;\n  margin-right: 15px;\n  margin-top: 2px;\n}\n\n.ts-service-info {\n  margin-left: 30px;\n}\n.ts-service-info h3 {\n  font-size: 16px;\n}\n.ts-service-info .learn-more {\n  text-transform: uppercase;\n  font-size: 14px;\n  font-weight: 600;\n}\n.ts-service-info .learn-more:hover {\n  color: #ffb600;\n}\n\n/* Service Classic */\n.ts-service-classic .ts-service-icon i {\n  font-size: 24px;\n  float: left;\n  color: #fff;\n  background: #ffb600;\n  border-radius: 100%;\n  width: 60px;\n  height: 60px;\n  line-height: 60px;\n  text-align: center;\n  transition: all 0.3s;\n}\n\n.ts-service-classic .ts-service-box-info {\n  margin-left: 80px;\n}\n\n.ts-service-classic:hover .ts-service-icon i {\n  background: #ffb600;\n}\n\n/* Projects area\n================================================== */\n/* Project filter nav */\n.shuffle-btn-group {\n  display: inline-block;\n  margin: 20px 0 50px;\n  width: 100%;\n  border-bottom: 3px solid #ffb600;\n}\n.shuffle-btn-group label {\n  display: inline-block;\n  color: #212121;\n  font-size: 14px;\n  padding: 6px 25px;\n  padding-top: 10px;\n  font-weight: 700;\n  text-transform: uppercase;\n  transition: all 0.3s;\n  cursor: pointer;\n  margin: 0;\n}\n.shuffle-btn-group label.active {\n  color: #212121;\n  background: #ffb600;\n}\n.shuffle-btn-group label input {\n  display: none;\n}\n\n/* Project shuffle Item */\n.shuffle-item {\n  padding: 0;\n}\n.shuffle-item .project-img-container {\n  position: relative;\n  overflow: hidden;\n}\n.shuffle-item .project-img-container img {\n  transform: perspective(1px) scale3d(1.1, 1.1, 1);\n  transition: all 400ms;\n}\n.shuffle-item .project-img-container:hover img {\n  transform: perspective(1px) scale3d(1.15, 1.15, 1);\n}\n.shuffle-item .project-img-container:after {\n  opacity: 0;\n  position: absolute;\n  content: \"\";\n  top: 0;\n  right: auto;\n  left: 0;\n  width: 100%;\n  height: 100%;\n  background-color: rgba(0, 0, 0, 0.7);\n  transition: all 400ms;\n}\n.shuffle-item .project-img-container:hover:after {\n  opacity: 1;\n}\n.shuffle-item .project-img-container .gallery-popup .gallery-icon {\n  position: absolute;\n  top: 0;\n  right: 0;\n  z-index: 1;\n  padding: 5px 12px;\n  background: #ffb600;\n  color: #fff;\n  opacity: 0;\n  transform: perspective(1px) scale3d(0, 0, 0);\n  transition: all 400ms;\n}\n.shuffle-item .project-img-container:hover .gallery-popup .gallery-icon {\n  opacity: 1;\n  transform: perspective(1px) scale3d(1, 1, 1);\n}\n.shuffle-item .project-img-container .project-item-info {\n  position: absolute;\n  top: 50%;\n  margin-top: -10%;\n  bottom: 0;\n  left: 0;\n  right: 0;\n  padding: 0 30px;\n  z-index: 1;\n}\n.shuffle-item .project-img-container .project-item-info-content {\n  opacity: 0;\n  transform: perspective(1px) translate3d(0, 15px, 0);\n  transition: all 400ms;\n}\n.shuffle-item .project-img-container .project-item-info-content .project-item-title {\n  font-size: 20px;\n}\n.shuffle-item .project-img-container .project-item-info-content .project-item-title a {\n  color: #fff;\n}\n.shuffle-item .project-img-container .project-item-info-content .project-item-title a:hover {\n  color: #ffb600;\n}\n.shuffle-item .project-img-container .project-item-info-content .project-cat {\n  background: #ffb600;\n  display: inline-block;\n  padding: 2px 8px;\n  font-weight: 700;\n  color: #000;\n  font-size: 10px;\n  text-transform: uppercase;\n}\n.shuffle-item .project-img-container:hover .project-item-info-content {\n  opacity: 1;\n  transform: perspective(1px) translate3d(0, 0, 0);\n}\n\n.general-btn .btn-primary:hover {\n  background: #000;\n}\n\n/* Project owl */\n.owl-theme.project-slide {\n  margin-top: 60px;\n}\n\n.project-slide .item {\n  position: relative;\n  overflow: hidden;\n  width: 100%;\n}\n\n.project-item img {\n  width: 100%;\n  max-width: auto;\n  transition: all 0.6s ease 0s;\n}\n\n.project-item:hover img {\n  transform: scale(1.1, 1.1);\n}\n\n.project-item-content {\n  position: absolute;\n  bottom: -1px;\n  padding: 15px 20px;\n  width: 100%;\n  background: #ffb600;\n}\n\n.owl-theme.project-slide .owl-nav > div {\n  position: absolute;\n  top: -70px;\n  right: 0;\n  transform: translateY(-50%);\n}\n\n.project-slide .owl-nav > div {\n  display: inline-block;\n  margin: 0 2px;\n  font-size: 20px;\n  background: #ffb600;\n  color: #fff;\n  width: 30px;\n  height: 30px;\n  line-height: 30px;\n  text-align: center;\n}\n\n.owl-theme.project-slide .owl-nav > .owl-prev {\n  right: 35px;\n  left: auto;\n}\n\n/* Projects Single page */\n.project-title {\n  font-size: 30px;\n}\n\n.project-info-label {\n  color: #303030;\n  font-weight: 700;\n  font-size: 14px;\n}\n\n.project-info-content {\n  font-size: 12px;\n}\n\n.project-info li {\n  margin-bottom: 5px;\n}\n\n.project-link {\n  margin-top: 15px;\n}\n\n/* Content area\n================================================== */\n/* Accordion */\n.accordion-group .card {\n  border-radius: 0;\n  margin-bottom: 10px;\n  border-bottom: 1px solid #dfdfdf !important;\n}\n.accordion-group .card-body {\n  padding: 15px 20px;\n}\n.accordion-group .card-body img {\n  max-width: 100px;\n  margin-bottom: 10px;\n}\n.accordion-group .card-header .btn {\n  font-size: 16px;\n  text-transform: uppercase;\n  font-weight: 700;\n  padding: 13px 15px;\n  padding-bottom: 10px;\n}\n.accordion-group .card-header .btn:before {\n  font-family: \"Font Awesome 5 Free\";\n  position: absolute;\n  z-index: 0;\n  font-size: 14px;\n  right: 16px;\n  padding: 3px 8px 1px;\n  text-align: center;\n  border-radius: 3px;\n  top: 12px;\n  content: \"\\f107\";\n  font-weight: 700;\n  background-color: #333;\n  color: #fff;\n  transition: 0.3s;\n}\n.accordion-group .card-header .btn[aria-expanded=true] {\n  color: #ffb600;\n}\n.accordion-group .card-header .btn[aria-expanded=true]::before {\n  content: \"\\f106\";\n  background-color: #ffb600;\n}\n.accordion-group.accordion-classic .card-header .btn:before {\n  display: none;\n}\n\n/* Clients */\n.clients-logo {\n  margin: 0 0 30px;\n  border: 1px solid #dadada;\n  min-height: 105px;\n  padding: 0 30px;\n  display: flex;\n  flex-direction: column;\n  justify-content: center;\n  align-items: center;\n  align-content: center;\n}\n\n.clients-logo img {\n  filter: grayscale(100%);\n  filter: gray;\n}\n\n/* Testimonial\n================================================== */\n.testimonial-area {\n  padding: 100px 0;\n  background-color: #ffb600;\n  background-image: url(../images/parallax2.jpg);\n  background-repeat: no-repeat;\n  background-size: cover;\n  background-attachment: fixed;\n  background-position: 50% 50%;\n}\n\n.testimonial-area .border-title,\n.testimonial-area .border-sub-title {\n  color: #fff;\n}\n\n.quote-item .quote-text {\n  margin: 0 0 10px;\n  display: inline-block;\n  padding: 0 40px 30px 60px;\n  background-color: #fff;\n  position: relative;\n  font-size: 16px;\n  font-style: italic;\n}\n@media (max-width: 992px) {\n  .quote-item .quote-text {\n    padding: 0 40px 30px 50px;\n  }\n}\n\n.quote-item .quote-text:before {\n  content: \"\\f10d\";\n  font-family: \"Font Awesome 5 Free\";\n  position: absolute;\n  font-size: 30px;\n  left: 0;\n  top: 0;\n  font-weight: 700;\n  color: #ffc009;\n}\n\n.testimonial-slide .slick-dots {\n  bottom: -35px;\n}\n\nimg.testimonial-thumb {\n  max-width: 80px;\n  float: left;\n  margin-right: 20px;\n  border-radius: 5px;\n}\n\n.quote-item-info {\n  padding-top: 15px;\n  display: inline-block;\n}\n\n.quote-author {\n  font-size: 16px;\n  line-height: 18px;\n  margin: 0 0 2px;\n  font-weight: 700;\n  display: block;\n  color: #ffb600;\n}\n\n.quote-item-footer {\n  margin-top: 0;\n  margin-left: 60px;\n}\n@media (max-width: 992px) {\n  .quote-item-footer {\n    margin-left: 0;\n  }\n}\n\n/* Testimonial Border */\n.quote-item.quote-border .quote-text-border {\n  border: 1px solid #ffb600;\n  padding: 20px;\n  position: relative;\n  line-height: 28px;\n  color: #666;\n  font-size: 18px;\n  text-align: center;\n}\n\n.quote-item.quote-border .quote-text-border:before {\n  border: 12px solid;\n  border-color: #e1e1e1 transparent transparent;\n  border-top-color: #ffb600;\n  bottom: -24px;\n  position: absolute;\n  content: \"\";\n  display: block;\n  height: 0;\n  width: 0;\n  left: 0;\n  margin: 0 auto;\n  right: 0;\n}\n\n.quote-item.quote-border .quote-text-border:after {\n  border: 12px solid;\n  border-color: #fff transparent transparent;\n  bottom: -22px;\n  position: absolute;\n  content: \"\";\n  display: block;\n  height: 0;\n  width: 0;\n  left: 0;\n  margin: 0 auto;\n  right: 0;\n}\n\n.quote-item.quote-border .quote-item-footer {\n  margin-left: 0;\n  text-align: center;\n  margin-top: 35px;\n}\n\n.quote-item.quote-border .quote-item-footer img.testimonial-thumb {\n  float: none;\n  margin: 0;\n}\n\n.quote-item.quote-border .quote-item-footer .quote-item-info {\n  display: block;\n}\n\n/* Subscribe area\n================================================== */\n.subscribe {\n  background: #ffb600;\n  padding: 0;\n}\n\n/* Call to action */\n.subscribe-call-to-acton {\n  min-height: 115px;\n  padding: 30px 0 0 30px;\n}\n@media (max-width: 992px) {\n  .subscribe-call-to-acton {\n    text-align: center;\n    padding: 30px 0;\n    min-height: auto;\n  }\n}\n\n.subscribe-call-to-acton h3 {\n  font-size: 18px;\n  margin-top: 0;\n  margin-bottom: 5px;\n}\n\n.subscribe-call-to-acton h4 {\n  color: #fff;\n  font-size: 24px;\n  margin: 0;\n}\n\n/* Newsletter */\n.ts-newsletter {\n  background: #252525;\n  position: relative;\n  min-height: 115px;\n  padding: 15px 0 0 50px;\n}\n@media (max-width: 992px) {\n  .ts-newsletter {\n    padding-top: 20px;\n    padding-bottom: 10px;\n  }\n}\n@media (max-width: 992px) {\n  .ts-newsletter {\n    padding: 30px 5px 15px 5px;\n    min-height: auto;\n    text-align: center;\n  }\n}\n.ts-newsletter:after {\n  content: \"\";\n  position: absolute;\n  background: #252525;\n  display: block;\n  width: 100%;\n  height: 100%;\n  right: -100%;\n  top: 0;\n}\n\n.newsletter-form input {\n  background: none;\n  font-size: 12px;\n  height: 45px;\n  border: 1px solid rgba(255, 255, 255, 0.3);\n}\n\n/* News section\n================================================== */\n.latest-post {\n  position: relative;\n}\n\n.latest-post .image-angle:before {\n  border-bottom: 20px solid #f9f9f9;\n}\n\n.latest-post .post-title {\n  font-size: 16px;\n  line-height: 24px;\n  margin: 0;\n  font-weight: 600;\n}\n\n.latest-post .post-title a {\n  color: #303030;\n}\n\n.latest-post .post-title a:hover {\n  color: #ffb600;\n}\n\n.latest-post-meta {\n  font-size: 13px;\n  text-transform: uppercase;\n}\n\n.latest-post .post-body {\n  padding: 20px 0 5px;\n}\n\n/* Footer\n================================================== */\n/*- Footer common */\n.footer {\n  background-color: #0d0d0d;\n  color: #999;\n}\n\n.footer-main {\n  padding: 80px 0 60px;\n}\n\n.footer .widget-title {\n  font-size: 16px;\n  font-weight: 700;\n  position: relative;\n  margin: 0 0 30px;\n  padding-left: 15px;\n  text-transform: uppercase;\n  color: #fff;\n  border-left: 3px solid #ffb600;\n}\n\n/* Footer about us */\n.footer-logo {\n  margin-bottom: 25px;\n}\n\n/* Footer social */\n.footer-social {\n  margin-top: 15px;\n}\n\n.footer-social .widget-title {\n  font-size: 14px;\n  margin-bottom: 10px;\n}\n\n.footer-social ul {\n  list-style: none;\n  margin: 0;\n  padding: 0;\n  margin-left: -13px;\n}\n.footer-social ul li {\n  display: inline-block;\n}\n.footer-social ul li a i {\n  display: block;\n  font-size: 16px;\n  color: #999;\n  transition: 400ms;\n  padding: 10px 13px;\n}\n.footer-social ul li:hover {\n  color: #fff;\n}\n\n/* Links */\n.footer-widget ul.list-arrow li {\n  border-bottom: 1px solid rgba(255, 255, 255, 0.07);\n  padding: 8px 0;\n}\n\n.footer-widget ul.list-arrow li:last-child {\n  border-bottom: 0;\n}\n\n.footer-widget ul.list-arrow li a,\n.footer-widget ul.list-arrow li:before {\n  color: #747474;\n}\n\n.footer-widget ul.list-arrow li:hover a,\n.footer-widget ul.list-arrow li:hover {\n  color: #ffb600;\n}\n\n.working-hours {\n  padding-right: 10px;\n}\n\n.working-hours .text-right {\n  float: right;\n}\n\n/*-- Copyright --*/\n.copyright {\n  background: #ffb600;\n  color: #111;\n  padding: 25px 0;\n  position: relative;\n  z-index: 1;\n  font-weight: 600;\n  font-size: 12px;\n}\n\n.footer-menu ul li {\n  display: inline-block;\n  line-height: 12px;\n  padding-left: 15px;\n}\n\n.footer-menu ul.nav li a {\n  background: none;\n  color: #111;\n  padding: 0;\n}\n\n.footer-menu ul li a:hover {\n  color: #fff;\n}\n\n#back-to-top {\n  right: 40px;\n  top: auto;\n  z-index: 10;\n  display: none;\n}\n#back-to-top .btn:focus {\n  outline: 0;\n  box-shadow: none;\n}\n@media (max-width: 992px) {\n  #back-to-top {\n    right: 15px;\n  }\n}\n\n#back-to-top.position-fixed {\n  bottom: 20px;\n}\n\n#back-to-top .btn.btn-primary {\n  width: 36px;\n  height: 36px;\n  line-height: 36px;\n  background: rgba(0, 0, 0, 0.9);\n  border-radius: 3px;\n  color: #ffb600;\n  font-weight: 700;\n  font-size: 16px;\n  padding: 0;\n}\n@media (max-width: 992px) {\n  #back-to-top .btn.btn-primary {\n    width: 32px;\n    height: 32px;\n    line-height: 32px;\n    font-size: 14px;\n  }\n}\n\n#back-to-top .btn.btn-primary:hover {\n  color: #fff;\n}\n\n/* Sub Pages\n================================================== */\n/*-- Title border --*/\n.main-container .border-left {\n  margin-bottom: 30px;\n}\n\n/*-- Banner --*/\n.banner-area {\n  position: relative;\n  min-height: 300px;\n  color: #fff;\n  background-position: 50% 50%;\n  background-size: cover;\n}\n\n.banner-title {\n  color: #fff;\n  text-transform: uppercase;\n  font-size: 58px;\n  font-weight: 900;\n}\n@media (max-width: 992px) {\n  .banner-title {\n    font-size: 48px;\n  }\n}\n@media (max-width: 992px) {\n  .banner-title {\n    font-size: 32px;\n  }\n}\n\n.banner-text {\n  position: absolute;\n  top: 50%;\n  left: 0;\n  right: 0;\n  max-width: 1170px;\n  margin: 0 auto;\n  width: 100%;\n  z-index: 1;\n  transform: translateY(-50%);\n}\n\n.banner-heading {\n  text-align: center;\n}\n\n.breadcrumb {\n  padding: 0;\n  background: none;\n  font-weight: 700;\n  text-transform: uppercase;\n  font-size: 12px;\n}\n.breadcrumb li a,\n.breadcrumb .breadcrumb-item,\n.breadcrumb li a:focus,\n.breadcrumb li a:hover {\n  color: #fff !important;\n}\n.breadcrumb .breadcrumb-item + .breadcrumb-item::before {\n  color: #fff;\n}\n\n/*-- About us page --*/\n/* Slider pages */\n.page-slider .carousel-control {\n  position: absolute;\n  top: 50%;\n  z-index: 5;\n  display: inline-block;\n  transform: translateY(-50%);\n  background-color: transparent;\n  text-shadow: none;\n  transition: all 0.25s ease;\n  padding: 0;\n  outline: 0;\n  border: 0;\n}\n.page-slider .carousel-control.left {\n  left: 0;\n}\n.page-slider .carousel-control.right {\n  right: 0;\n}\n.page-slider .carousel-control i {\n  background: rgba(0, 0, 0, 0.3);\n  color: #fff;\n  line-height: 70px;\n  width: 40px;\n  height: 70px;\n  font-size: 22px;\n  border-radius: 0;\n  transition: all 500ms ease;\n}\n.page-slider .carousel-control i:hover {\n  background: #ffb600;\n  color: #fff;\n}\n\n.page-slider.small-bg .item {\n  min-height: 330px;\n  background-size: cover;\n}\n\n.page-slider.small-bg .box-slider-content {\n  left: 20%;\n}\n\n.page-slider.small-bg .box-slider-text {\n  background: rgba(0, 0, 0, 0.55);\n  padding: 5px 20px;\n}\n\n.page-slider.small-bg .box-slide-title {\n  font-size: 28px;\n  color: #fff;\n  font-weight: 900;\n}\n\n/*-- Get a quote page --*/\n.page-quote-form {\n  background: #f2f2f2;\n  padding: 30px 50px 50px;\n}\n\n.get-a-quote-img {\n  margin-bottom: -190px;\n}\n\n/*-- Partners carousel --*/\n.partner-logo {\n  border: 1px solid #eee;\n  padding: 20px;\n  margin-top: 40px;\n  margin-bottom: 10px;\n}\n\n.partner-logo img {\n  transition: 350ms;\n  opacity: 0.6;\n  filter: grayscale(100%);\n}\n\n.partner-logo:hover img {\n  opacity: 1;\n  filter: grayscale(0%);\n}\n\n#partners-carousel .partner-logo {\n  border: 0;\n  border-right: 1px solid #eee;\n  padding: 0 15px;\n  margin-top: 20px;\n}\n\n#partners-carousel .partner-logo.last {\n  border-right: 0;\n}\n\n/*-- Team page --*/\n.team-slide .slick-slide {\n  margin-left: 25px;\n  padding-bottom: 60px;\n}\n.team-slide .slick-list {\n  margin-left: -25px;\n}\n.team-slide .carousel-control {\n  position: absolute;\n  bottom: 0;\n  left: 50%;\n  border: 0;\n  background-color: #ddd;\n  height: 37px;\n  width: 37px;\n  border-radius: 4px;\n  transition: 0.3s;\n  z-index: 6;\n}\n.team-slide .carousel-control:hover {\n  background-color: #ffb600;\n  color: #fff;\n}\n.team-slide .carousel-control.left {\n  transform: translateX(calc(-50% - 25px));\n}\n.team-slide .carousel-control.right {\n  transform: translateX(calc(-50% + 25px));\n}\n.team-slide .carousel-control.slick-disabled {\n  opacity: 0.4;\n}\n.team-slide .carousel-control.slick-disabled:hover {\n  background-color: #ddd;\n  color: #000;\n}\n\n.ts-team-wrapper {\n  position: relative;\n  overflow: hidden;\n}\n.ts-team-wrapper .ts-team-content {\n  position: absolute;\n  top: 76%;\n  left: 0;\n  width: 100%;\n  height: 100%;\n  padding: 15px 25px;\n  margin-top: 0;\n  color: #fff;\n  background: rgba(0, 0, 0, 0.5);\n  transition: 350ms;\n}\n@media (min-width: 992px) {\n  .ts-team-wrapper .ts-team-content {\n    top: 72%;\n  }\n}\n@media (max-width: 992px) {\n  .ts-team-wrapper .ts-team-content {\n    text-align: center;\n  }\n}\n.ts-team-wrapper .ts-name {\n  font-size: 16px;\n  margin-top: 0;\n  margin-bottom: 3px;\n  line-height: normal;\n  color: #ffb600;\n}\n.ts-team-wrapper .ts-designation {\n  color: #fff;\n  font-size: 14px;\n  margin-bottom: 15px;\n  font-weight: 700;\n}\n.ts-team-wrapper .team-social-icons a i {\n  color: #fff;\n  margin-right: 8px;\n  text-align: center;\n  transition: 400ms;\n}\n.ts-team-wrapper .team-social-icons a i:hover {\n  color: #ffb600;\n}\n.ts-team-wrapper:hover .ts-team-content {\n  top: 0;\n  padding-top: 50px;\n}\n\n/* Team Classic */\n.ts-team-content-classic {\n  margin-top: 15px;\n}\n.ts-team-content-classic .ts-name {\n  font-size: 16px;\n  margin-bottom: 5px;\n  color: #212121;\n}\n.ts-team-content-classic .ts-designation {\n  color: #888;\n  margin-bottom: 5px;\n  font-weight: 600;\n}\n.ts-team-content-classic .team-social-icons a i {\n  color: #999;\n}\n.ts-team-content-classic .team-social-icons a i:hover {\n  color: #ffb600;\n}\n\n/*-- Pricing table  --*/\n.ts-pricing-box {\n  margin: 20px 0;\n  padding: 0;\n  text-align: center;\n  background: #f9f9f9;\n}\n.ts-pricing-box .ts-pricing-header {\n  background: #252525;\n  color: #fff;\n  position: relative;\n  padding: 30px 20px;\n}\n.ts-pricing-box .ts-pricing-name {\n  font-size: 18px;\n  line-height: normal;\n  margin: 0 0 5px 0;\n  color: #fff;\n}\n.ts-pricing-box .ts-pricing-price {\n  font-size: 44px;\n  color: #fff;\n  margin: 15px 0 0;\n  display: inline-block;\n}\n.ts-pricing-box .ts-pricing-price > small {\n  font-size: 16px;\n  line-height: 16px;\n  display: block;\n  margin-top: 15px;\n  color: #fff;\n}\n.ts-pricing-box .ts-pricing-features {\n  padding: 15px 0;\n}\n.ts-pricing-box .ts-pricing-features ul {\n  padding: 0 20px;\n}\n.ts-pricing-box .ts-pricing-features ul > li {\n  padding: 20px 0;\n  border-top: 1px dotted #e5e5e5;\n}\n.ts-pricing-box .ts-pricing-features ul > li:first-child {\n  border-top: 0;\n}\n.ts-pricing-box .plan-action {\n  padding-bottom: 40px;\n}\n\n/* Pricing featured */\n.ts-pricing-box.ts-pricing-featured .ts-pricing-header {\n  background: #ffb600;\n}\n\n/* Contact Us\n================================================== */\n.map {\n  height: 450px;\n  z-index: 1;\n}\n\n.contact-info-box {\n  margin-top: 20px;\n}\n\n.contact-info-box i {\n  float: left;\n  font-size: 24px;\n  color: #ffb600;\n}\n\n.contact-info-box-content {\n  padding-left: 40px;\n}\n\n.contact-info-box-content h4 {\n  font-size: 16px;\n  margin-top: 0;\n  line-height: normal;\n  font-weight: 700;\n}\n\n.contact-info-box-content p {\n  margin-bottom: 0;\n}\n\nlabel {\n  font-weight: 400;\n}\n\n/* Contact page 2 */\n.ts-service-box.text-center .ts-service-icon.icon-squre i {\n  float: none;\n  margin-bottom: 20px;\n}\n\n.ts-service-box.text-center .ts-service-box-content {\n  margin: 0;\n}\n\n/* News Listing\n================================================== */\n.post {\n  border-bottom: 1px solid #dadada;\n  padding: 0 0 30px;\n  margin: 0 0 45px;\n}\n\n.post.last {\n  padding-bottom: 0;\n  margin-bottom: 0;\n  border-bottom: 0;\n}\n\n.post-body {\n  padding: 20px 0;\n}\n\n.entry-header .entry-title {\n  font-size: 24px;\n  margin: 5px 0 15px;\n  position: relative;\n  line-height: 34px;\n  text-transform: capitalize;\n}\n\n.entry-header .entry-title a {\n  color: #303030;\n}\n\n.entry-header .entry-title a:hover {\n  color: #ffb600;\n}\n\n.post-single .entry-header .entry-title {\n  font-size: 28px;\n}\n\n/* Meta */\n.post-meta {\n  padding-bottom: 10px;\n}\n\n.post-meta a {\n  color: #303030;\n}\n\n.post-meta a:hover {\n  color: #ffb600;\n}\n\n.post-meta span {\n  margin-right: 10px;\n  padding-right: 10px;\n  border-right: 1px solid #dadada;\n  line-height: 12px;\n  display: inline-block;\n}\n\n.post-meta i {\n  color: #bbb;\n  margin-right: 3px;\n}\n\n.post-meta .post-comment {\n  border-right: 0;\n}\n\n.post-meta .post-comment .comments-link {\n  margin-left: 5px;\n}\n\n.post-footer .btn.btn-primary {\n  font-size: 12px;\n  margin-top: 10px;\n}\n\n/* Pagination */\n.paging {\n  margin-bottom: -5px;\n}\n\n.pagination li a {\n  border-radius: 0 !important;\n  margin-right: 8px;\n  color: #7c7c7c;\n}\n\n.pagination > .active > a,\n.pagination > .active > a:hover,\n.pagination > li > a:hover {\n  color: #fff;\n  background: #ffb600;\n  border: 1px solid transparent;\n}\n\n/* News Single\n================================================== */\n.tags-area {\n  margin: 20px 0;\n}\n\n.post-tags a {\n  border: 1px solid #dadada;\n  color: #7c7c7c;\n  display: inline-block;\n  font-size: 12px;\n  padding: 3px 10px;\n  margin-left: 3px;\n}\n\n.post-tags a:hover {\n  background: #ffb600;\n  color: #fff;\n  border: 1px solid transparent;\n}\n\n/* Post social */\n.post-social-icons > li {\n  display: inline-block;\n}\n\n.post-social-icons a i {\n  margin-left: 5px;\n  font-size: 12px;\n  width: 28px;\n  height: 26px;\n  line-height: 26px;\n  color: #fff;\n  text-align: center;\n}\n\n.post-social-icons a i.fa-facebook-f {\n  background: #41578a;\n}\n\n.post-social-icons a i.fa-twitter {\n  background: #64bae2;\n}\n\n.post-social-icons a i.fa-google-plus {\n  background: #c0343d;\n}\n\n.post-social-icons a i.fa-linkedin {\n  background: #3397b6;\n}\n\n/* Author box */\n.author-box {\n  border: 1px solid #dadada;\n  padding: 20px 20px 15px;\n  margin: 20px 0;\n}\n\n.author-img img {\n  width: 110px;\n  height: 110px;\n  margin-right: 30px;\n}\n\n.author-info h3 {\n  margin-top: 0;\n  margin-bottom: 5px;\n  font-size: 18px;\n  font-weight: 600;\n}\n\n.author-info h3 span {\n  font-size: 12px;\n  color: #999;\n  border-left: 1px solid #afafaf;\n  padding-left: 10px;\n  margin-left: 10px;\n  font-weight: 500;\n}\n\n/* Comments area */\n.comments-area {\n  margin: 40px 0;\n}\n\n.comments-list .comment-content {\n  margin: 15px 0;\n}\n\n.comments-list .comment-reply {\n  color: #303030;\n  font-weight: 400;\n}\n\n.comments-list .comment-reply:hover {\n  color: #ffb600;\n}\n\n.comments-counter {\n  font-size: 18px;\n}\n\n.comments-counter a {\n  color: #323232;\n}\n\n.comments-list {\n  list-style: none;\n  margin: 0;\n  padding: 20px 0;\n}\n\n.comments-list .comment {\n  border-bottom: 1px solid #e7e7e7;\n  padding-bottom: 20px;\n  margin-bottom: 30px;\n}\n\n.comments-list .comment.last {\n  border-bottom: 0;\n  padding-bottom: 0;\n  margin-bottom: 0;\n}\n\n.comments-list img.comment-avatar {\n  width: 84px;\n  height: 84px;\n  margin-right: 30px;\n}\n@media (max-width: 992px) {\n  .comments-list img.comment-avatar {\n    width: 40px;\n    height: 40px;\n    margin-right: 25px;\n  }\n}\n\n.comments-list .comment-author {\n  margin-bottom: 0;\n  margin-top: 0;\n  font-weight: 600;\n  font-size: 16px;\n  color: #303030;\n}\n\n.comments-list .comment-date {\n  color: #959595;\n  margin-bottom: 5px;\n  font-size: 12px;\n}\n@media (max-width: 992px) {\n  .comments-list .comment-date {\n    float: none !important;\n    display: inline-block;\n  }\n}\n\n.comments-reply {\n  list-style: none;\n  margin: 0 0 0 70px;\n}\n@media (max-width: 992px) {\n  .comments-reply {\n    margin: 0;\n    padding: 0;\n  }\n}\n\n.comments-form {\n  margin-bottom: 0;\n}\n\n.comments-form .title-normal {\n  margin-bottom: 20px;\n}\n\n.comments-form .btn.btn-primary {\n  margin-top: 20px;\n}\n\n/* Sidebar\n================================================== */\n.sidebar .widget-title {\n  font-size: 16px;\n  font-weight: 700;\n  position: relative;\n  margin: 0 0 30px;\n  padding-left: 15px;\n  text-transform: uppercase;\n  border-left: 3px solid #ffb600;\n}\n\n/* Widget common */\n.sidebar .widget {\n  margin-bottom: 40px;\n}\n\n.sidebar-left .widget {\n  margin-right: 20px;\n}\n\n.sidebar-right .widget {\n  margin-left: 20px;\n}\n\n.sidebar .widget.box {\n  padding: 25px;\n}\n\n.widget.box.solid {\n  background: #f2f2f2;\n}\n\n.widget.box.red {\n  background: #ec483b;\n  color: #fff;\n}\n\n.widget.box.red .widget-title {\n  color: #fff;\n}\n\n.widget ul li {\n  line-height: 30px;\n}\n\n.sidebar .widget ul li a {\n  color: #303030;\n}\n\n.sidebar .widget ul li a:hover {\n  color: #ffb600;\n}\n\n.sidebar .widget ul li i {\n  margin-right: 5px;\n}\n\n.sidebar .btn {\n  font-weight: 700;\n  font-size: 12px;\n  margin-top: 15px;\n  padding: 10px 25px;\n}\n\n/* Sidebar nav */\n.sidebar ul.nav-tabs {\n  border: 0;\n}\n\n.sidebar ul.nav-tabs li {\n  width: 100%;\n}\n.sidebar ul.nav-tabs li a {\n  color: #303030;\n  border-radius: 0;\n  padding: 15px 0;\n  padding-left: 0;\n  font-weight: 400;\n  border-bottom: 1px solid #ddd;\n  display: block;\n  transition: 400ms;\n}\n\n.sidebar ul.nav-tabs li.active a,\n.sidebar ul.nav-tabs li:hover a {\n  color: #ffb600;\n}\n\n.sidebar ul.nav-tabs li {\n  color: #303030;\n  line-height: normal;\n}\n\n.sidebar ul.nav-tabs li:last-child a {\n  border-bottom: 0;\n}\n\n/* Service menu */\n.sidebar ul.service-menu li {\n  width: 100%;\n}\n.sidebar ul.service-menu li a {\n  background-color: #f4f4f4;\n  padding: 15px 20px;\n  border: 0;\n  margin-bottom: 8px;\n  position: relative;\n  transition: 400ms;\n  display: block;\n}\n.sidebar ul.service-menu li.active a, .sidebar ul.service-menu li:hover a {\n  background: #ffb600;\n  color: #fff;\n  cursor: pointer;\n}\n\n/* Recent News */\n.widget.recent-posts .widget-title {\n  margin-bottom: 35px;\n}\n\n.widget.recent-posts ul li {\n  border-bottom: 1px solid #dadada;\n  padding-bottom: 15px;\n  margin-bottom: 17px;\n}\n.widget.recent-posts ul li:last-child {\n  border: 0;\n  padding-bottom: 0;\n  margin-bottom: 0;\n}\n.widget.recent-posts .posts-thumb img {\n  margin-right: 15px;\n  width: 90px;\n  height: 70px;\n}\n.widget.recent-posts .post-info .entry-title {\n  font-size: 13px;\n  font-weight: 600;\n  line-height: 20px;\n  margin: 0;\n}\n.widget.recent-posts .post-info .entry-title a {\n  color: #303030;\n  display: inline-block;\n}\n.widget.recent-posts .post-info .entry-title a:hover {\n  color: #ffb600;\n}\n.widget.recent-posts .post-date {\n  font-weight: 400;\n  color: #999;\n  text-transform: capitalize;\n}\n\n/* Widget tags */\n.widget-tags ul > li {\n  float: left;\n  margin: 3px;\n}\n\n.sidebar .widget-tags ul > li a {\n  border: 1px solid #dadada;\n  color: #303030;\n  display: block;\n  font-size: 14px;\n  padding: 3px 15px;\n  transition: all 0.3s ease 0s;\n}\n\n.sidebar .widget-tags ul > li a:hover {\n  background: #ffb600;\n  color: #fff;\n  border: 1px solid transparent;\n}\n\n/* Error page\n================================================== */\n.error-page .error-code h2 {\n  display: block;\n  font-size: 200px;\n  line-height: 200px;\n  color: #303030;\n  margin-bottom: 20px;\n}\n\n.error-page .error-body .btn {\n  margin-top: 30px;\n  font-weight: 700;\n}","/* Global styles\n================================================== */\n\nhtml {\n  overflow-x: hidden !important;\n  width: 100%;\n  height: 100%;\n  position: relative;\n  -webkit-font-smoothing: antialiased;\n  text-rendering: optimizeLegibility;\n}\n\nbody {\n  border: 0;\n  margin: 0;\n  padding: 0;\n}\n\n.body-inner {\n  position: relative;\n  overflow: hidden;\n}\n\n.preload {\n  position: fixed;\n  background: #fff url(../images/preload.gif) center center no-repeat;\n  left: 0px;\n  top: 0px;\n  width: 100%;\n  height: 100%;\n  z-index: 99999;\n}\n\na:link,\na:visited {\n  text-decoration: none;\n}\n\na {\n  color: inherit;\n  transition: 0.2s ease;\n}\n\na:hover {\n  text-decoration: none;\n  color: #000;\n}\n\na.read-more {\n  color: #ffb600;\n  font-weight: 700;\n  text-transform: uppercase;\n}\n\na.read-more:hover {\n  color: #222;\n}\n\nsection,\n.section-padding {\n  padding: 70px 0;\n  position: relative;\n}\n\n.no-padding {\n  padding: 0;\n}\n\n.gap-60 {\n  clear: both;\n  height: 60px;\n}\n\n.gap-40 {\n  clear: both;\n  height: 40px;\n}\n\n.gap-30 {\n  clear: both;\n  height: 30px;\n}\n\n.gap-20 {\n  clear: both;\n  height: 20px;\n}\n\n.mrb-30 {\n  margin-bottom: 30px;\n}\n\n.mrb-80 {\n  margin-bottom: -80px;\n}\n\n.mrt-0 {\n  margin-top: 0 !important;\n  margin-bottom: 20px !important;\n}\n\n.pab {\n  padding-bottom: 0;\n}\n\na:focus {\n  outline: 0;\n}\n\n.ts-padding {\n  padding: 60px;\n}\n\n.solid-bg {\n  background: #f9f9f9;\n}\n\n.dark-bg {\n  background: #252525;\n  color: #fff;\n}\n\n.dark-bg h2,\n.dark-bg h3 {\n  color: #fff;\n}\n\n.solid-row {\n  background: #f0f0f0;\n}\n\n.bg-overlay {\n  position: relative;\n}\n\n.bg-overlay .container {\n  position: relative;\n  z-index: 1;\n}\n\n.bg-overlay:after {\n  background-color: rgba(0, 46, 91, 0.8);\n  z-index: 0;\n  position: absolute;\n  content: \"\";\n  width: 100%;\n  height: 100%;\n  top: 0;\n  left: 0;\n}\n\n.bg-overlay:after {\n  position: relative;\n}\n\n.bg-overlay:after {\n  background-color: rgba(0, 0, 0, 0.8);\n  z-index: 0;\n  position: absolute;\n  content: \"\";\n  width: 100%;\n  height: 100%;\n  top: 0;\n  left: 0;\n}\n\n.content-hidden {\n  position: absolute;\n  height: 1px;\n  width: 1px;\n  clip: rect(1px, 1px, 1px, 1px);\n  border: 0;\n  overflow: hidden;\n}\n\n/* Dropcap */\n\n.dropcap {\n  font-size: 48px;\n  line-height: 60px;\n  padding: 0 7px;\n  display: inline-block;\n  font-weight: 700;\n  margin: 5px 15px 5px 0;\n  position: relative;\n  text-transform: uppercase;\n}\n\n.dropcap.primary {\n  background: #ffb600;\n  color: #fff;\n}\n\n.dropcap.secondary {\n  background: #3a5371;\n  color: #fff;\n}\n\n/* Title */\n\n.title {\n  font-size: 32px;\n  line-height: 36px;\n  margin-bottom: 20px;\n}\n\n/* Title Border */\n\n/* Section title */\n.section-title {\n  font-size: 18px;\n  line-height: 28px;\n  margin: 0;\n  text-transform: uppercase;\n  font-weight: 300;\n}\n\n.section-sub-title {\n  font-weight: 900;\n  font-size: 30px;\n  line-height: 46px;\n  margin: 0 0 60px;\n  color: #212121;\n}\n\n/* Column title */\n\n.column-title {\n  margin: 0 0 40px;\n}\n\n.column-title-small {\n  font-size: 20px;\n  margin: 0 0 25px;\n}\n\n/* Page content title */\n\n.page-content-title.first {\n  margin-top: 0;\n}\n\n/* Video responsive */\n\n.embed-responsive {\n  padding-bottom: 56.25%;\n  position: relative;\n  display: block;\n  height: 0;\n  overflow: hidden;\n}\n\n.embed-responsive iframe {\n  position: absolute;\n  top: 0;\n  left: 0;\n  width: 100%;\n  height: 100%;\n  border: 0;\n}\n\n/* Input form */\n\n.form-control {\n  box-shadow: none;\n  border: 1px solid #dadada;\n  padding: 5px 20px;\n  height: 44px;\n  background: none;\n  color: #959595;\n  font-size: 14px;\n  border-radius: 0;\n}\n\n.form-control:focus {\n  box-shadow: none;\n  border: 1px solid #ffb600;\n}\n\nhr {\n  background-color: #e7e7e7;\n  border: 0;\n  height: 1px;\n  margin: 40px 0;\n}\n\n.alert hr {\n  background: initial;\n  margin: initial;\n  border-top: 1px solid;\n  height: initial;\n  margin-bottom: 1rem;\n  opacity: 0.2;\n}\n\nblockquote {\n  padding: 25px;\n  margin: 20px 0;\n  background: #f9f9f9;\n  position: relative;\n  border-left: 3px solid #ffb600;\n  padding-left: 40px;\n  &.text-center {\n    border-top: 3px solid #ffb600;\n    border-left: 0;\n    padding-left: 25px;\n    padding-top: 50px;\n    &:before {\n      left: 50%;\n      top: 10px;\n      transform: translateX(-50%);\n    }\n  }\n  &.text-right {\n    border-right: 3px solid #ffb600;\n    padding-right: 40px;\n    border-left: 0;\n    padding-left: 25px;\n    &:before {\n      left: auto;\n      right: 5px;\n    }\n  }\n\n  &:before {\n    content: \"\\f10d\";\n    font-family: \"Font Awesome 5 Free\";\n    position: absolute;\n    font-size: 28px;\n    color: #e5e5e5;\n    top: 5px;\n    left: 5px;\n    font-weight: 700;\n    z-index: 0;\n  }\n}\n\nblockquote p {\n  font-size: 14px;\n  line-height: 22px;\n  position: relative;\n  z-index: 1;\n  font-style: italic;\n  margin-bottom: 0;\n}\n\ncite {\n  display: block;\n  font-size: 14px;\n  margin-top: 10px;\n}\n\n/* Ul, Ol */\n\n.list-round,\n.list-arrow,\n.list-check {\n  list-style: none;\n  margin: 0;\n  padding: 0 0 0 15px;\n}\n\n.list-round li {\n  line-height: 28px;\n}\n\n.list-round li:before {\n  font-family: \"Font Awesome 5 Free\";\n  content: \"\\f138\";\n  margin-right: 10px;\n  color: #ffb600;\n  font-size: 12px;\n}\n\n.list-arrow {\n  padding: 0;\n}\n\nul.list-arrow li:before {\n  font-family: \"Font Awesome 5 Free\";\n  content: \"\\f105\";\n  margin-right: 10px;\n  color: #ffb600;\n  font-size: 16px;\n  font-weight: bold;\n}\n\nul.list-check li:before {\n  font-family: \"Font Awesome 5 Free\";\n  content: \"\\f00c\";\n  margin-right: 10px;\n  color: #ffb600;\n  font-size: 14px;\n}\n\n/* Bootstrap */\n\n.nav-tabs > li.active > a,\n.nav-tabs > li.active > a:focus,\n.nav-tabs > li.active > a:hover,\n.nav-tabs > li > a:hover,\n.nav-tabs > li > a {\n  border: 0;\n}\n\n.nav > li > a:focus,\n.nav > li > a:hover {\n  background: none;\n}\n\n.pattern-bg {\n  background: #f5f5f5 url(../images/crossword.png);\n}\n\na[href^=\"tel\"] {\n  color: inherit;\n  text-decoration: none;\n}\n","/* Button */\n.btn {\n  &:active,\n  &:focus {\n    box-shadow: none !important;\n  }\n}\n.btn-primary,\n.btn-dark {\n  border: 0;\n  border-radius: 3px;\n  padding: 12px 20px 10px;\n  font-weight: 700;\n  text-transform: uppercase;\n  color: #fff;\n  font-family: \"Montserrat\", sans-serif;\n  transition: 350ms;\n  font-size: 14px;\n  @media (max-width: 992px) {\n    font-size: 13px;\n  }\n}\n\n.btn-white.btn-primary {\n  background: #fff;\n  color: #ffb600;\n}\n\n.btn-primary {\n  background: #ffb600;\n}\n\n.btn-dark {\n  background: #23282d;\n}\n\n.btn-primary:hover,\n.btn-dark:hover,\n.btn-white.btn-primary:hover {\n  background: #111;\n  color: #fff;\n  &:active,\n  &:focus {\n    color: #fff;\n    background-color: #111 !important;\n  }\n}\n\n.general-btn {\n  margin-top: 50px;\n}\n","/* Bootstrap */\n\n.nav-tabs > li.active > a,\n.nav-tabs > li.active > a:focus,\n.nav-tabs > li.active > a:hover,\n.nav-tabs > li > a:hover,\n.nav-tabs > li > a {\n  border: 0;\n}\n\n.nav > li > a:focus,\n.nav > li > a:hover {\n  background: none;\n}\n\n.pattern-bg {\n  background: #f5f5f5 url(../images/crossword.png);\n}\n\na[href^=\"tel\"] {\n  color: inherit;\n  text-decoration: none;\n}\n\n/* Top Bar\n================================================== */\n\n.top-bar {\n  padding: 8px 0;\n  background: #ebebeb;\n  position: relative;\n}\n\n/* Top info */\n\nul.top-info {\n  list-style: none;\n  margin: 0;\n  padding: 0;\n}\n\nul.top-info li {\n  position: relative;\n  line-height: 10px;\n  display: inline-block;\n  margin-left: 0;\n  padding-right: 15px;\n}\n\nul.top-info li i {\n  font-size: 18px;\n  position: relative;\n  top: 2px;\n  margin-right: 5px;\n}\n\nul.top-info li p.info-text {\n  margin: 0;\n  line-height: normal;\n  display: inline-block;\n  -webkit-flex-direction: column;\n  -ms-flex-direction: column;\n  flex-direction: column;\n}\n\n/* Top social */\n\n.top-social ul {\n  list-style: none;\n  padding: 0;\n  margin: 0;\n  margin-right: -12px;\n  @media (max-width: 992px) {\n    margin-right: 0;\n  }\n  li {\n    display: inline-block;\n    padding: 0;\n    a {\n      color: #2c2c2c;\n      font-size: 14px;\n      transition: 400ms;\n      padding: 9px 12px;\n      &:hover {\n        color: #333;\n      }\n    }\n  }\n}\n\n/* Top bar border */\n\n.top-bar-border {\n  padding: 8px 20px 8px;\n  border-bottom: 1px solid #ddd;\n}\n\n.top-bar-border ul.top-info {\n  color: #707070;\n  font-weight: 400;\n}\n\n.top-bar-border .top-social li a {\n  color: #7c7c7c;\n}\n\n.top-bar-border ul.top-info li i {\n  color: #ffb600;\n}\n\n/* Header area\n================================================== */\n.header {\n  background: #fff;\n  position: relative;\n  box-shadow: 0px 3px 3px rgba(0, 0, 0, 0.1);\n}\n\n.header-one,\n.header-one .site-navigation {\n  background: #23282d;\n}\n.header-one .navbar-collapse {\n  padding-left: 0;\n}\n.navbar-collapse.collapse {\n  @media (min-width: 992px) {\n    overflow-y: auto;\n  }\n}\n.header-one {\n  ul.navbar-nav > li {\n    padding-left: 0;\n    padding-right: 30px;\n    @media (min-width: 992px) {\n      padding-right: 0;\n    }\n  }\n  .logo-area {\n    padding: 30px 0;\n  }\n}\n\n.navbar-fixed {\n  z-index: 9999;\n  position: fixed;\n  width: 100%;\n  top: 0;\n}\n\n.header-two {\n  background: #fff;\n  box-shadow: 0 2px 2px 0 rgba(0, 0, 0, 0.15);\n  padding: 15px 0;\n  .navbar-fixed {\n    background-color: #fff;\n  }\n}\nul.navbar-nav > li > a {\n  padding: 15px 0 !important;\n  color: #fff;\n}\n@media (min-width: 992px) {\n  ul.navbar-nav > li > a {\n    padding: 1px 0 !important;\n  }\n  .navbar-nav {\n    margin-bottom: 15px;\n  }\n}\nul.navbar-nav > li:hover > a,\nul.navbar-nav > li.active > a {\n  color: #ffb600 !important;\n}\n\n/*-- Logo --*/\n.logo img {\n  width: auto;\n  height: 35px;\n}\n.header-two .logo img {\n  height: 30px;\n}\n\n/* header right */\n\n.header-right {\n  float: right;\n}\n\nul.top-info-box {\n  list-style: none;\n  margin: 0;\n  padding: 0;\n  float: right;\n  @media (max-width: 992px) {\n    display: flex;\n    justify-content: center;\n    flex-wrap: wrap;\n    align-items: center;\n  }\n}\n\nul.top-info-box li {\n  position: relative;\n  float: left;\n  margin-left: 0;\n  border-right: 1px solid #dedede;\n  border-right: 1px solid rgba(0, 0, 0, 0.1);\n  padding-right: 25px;\n  margin-right: 25px;\n  @media (max-width: 992px) {\n    border: 0;\n    text-align: center;\n    margin: 0;\n    flex: 0 0 50%;\n    padding: 0;\n    margin-top: 10px;\n  }\n  @media (max-width: 992px) {\n    border: 0;\n    text-align: center;\n    margin: 0;\n    flex: 0 0 100%;\n    margin-top: 15px;\n  }\n}\n\nul.top-info-box li:last-child {\n  margin-right: 0;\n  padding-right: 0;\n  border-right: 0;\n}\n\nul.top-info-box li.last {\n  border-right: 0;\n}\n\nul.top-info-box li .info-box span.info-icon {\n  font-size: 20px;\n  display: inline-block;\n  text-align: center;\n  margin: 2px 5px 0 0;\n  position: relative;\n}\n\nul.top-info-box li .info-box .info-box-content {\n  display: inline-block;\n  font-family: \"Montserrat\", sans-serif;\n  -webkit-flex-direction: column;\n  -ms-flex-direction: column;\n  flex-direction: column;\n}\n\nul.top-info-box li .info-box .info-box-title {\n  font-size: 14px;\n  margin-bottom: 8px;\n  line-height: normal;\n}\n\nul.top-info-box li .info-box .info-box-subtitle {\n  margin: 0;\n  line-height: normal;\n  font-size: 15px;\n  font-weight: 700;\n  color: #111;\n}\n\n/*-- Search start --*/\n\nul.top-info-box > li.nav-search {\n  cursor: pointer;\n  padding-left: 30px;\n  margin-left: 30px;\n}\n\nul.top-info-box > li.nav-search:before {\n  position: absolute;\n  content: \"\";\n  background: #ddd;\n  left: 0;\n  width: 1px;\n  height: 40px;\n  top: 50%;\n  margin-top: -10px;\n}\n\nul.top-info-box > li.nav-search i {\n  font-size: 20px;\n  top: 10px;\n  position: relative;\n  cursor: pointer;\n  color: #999;\n}\n\n/* Main navigation */\n\n.navbar-toggler {\n  float: left;\n  margin-top: 10px;\n  padding: 12px;\n}\n\n.navbar {\n  border-radius: 0;\n  border: 0;\n  margin-bottom: 0;\n}\n\n.navbar-toggler {\n  margin: 10px 0;\n  padding: 6px;\n  border-radius: 0;\n  font-size: 1rem;\n  background: #ffb600;\n  &:focus {\n    outline: 0;\n  }\n}\n.navbar-dark .navbar-toggler-icon,\n.navbar-light .navbar-toggler-icon {\n  background-image: url(\"data:image/svg+xml,%3csvg xmlns='http://www.w3.org/2000/svg' width='30' height='30' viewBox='0 0 30 30'%3e%3cpath stroke='rgba%28255, 255, 255, 1' stroke-linecap='round' stroke-miterlimit='10' stroke-width='2' d='M4 7h22M4 15h22M4 23h22'/%3e%3c/svg%3e\");\n}\n\nul.navbar-nav > li:hover > a,\nul.navbar-nav > li.active > a {\n  color: #ffb600;\n  position: relative;\n}\n\nul.navbar-nav > li {\n  padding: 0 13px;\n  position: relative;\n  @media (min-width: 992px) {\n    padding: 0 9px;\n    .nav-link {\n      font-size: 12px;\n    }\n  }\n}\n.header-two {\n  .navbar-nav > .header-get-a-quote {\n    top: -4px;\n  }\n}\n\n.header-two ul.navbar-nav > li {\n  @media (min-width: 992px) {\n    padding: 0;\n    width: 100%;\n  }\n}\n\nul.navbar-nav > li:last-child {\n  padding-right: 0;\n}\n\nul.navbar-nav > li:last-child:after {\n  background: none;\n}\n\nul.navbar-nav > li > a:hover,\nul.navbar-nav > li > a:focus {\n  background: none;\n}\n\nul.navbar-nav > li > a i {\n  font-weight: 700;\n}\n@media (min-width: 992px) {\n  ul.navbar-nav > li > a i {\n    float: right;\n    background: #222;\n    padding: 6px 10px;\n    margin-top: 7px;\n  }\n  .header-two {\n    ul.navbar-nav > li > a i {\n      color: #fff;\n    }\n    ul.navbar-nav > li.active > a i,\n    ul.navbar-nav > li > a.active i {\n      color: #ffb600;\n    }\n  }\n}\n\nul.navbar-nav > li > a:after,\nul.navbar-nav > li > a:after {\n  display: none;\n}\n\nul.navbar-nav > li > a {\n  font-family: \"Montserrat\", sans-serif;\n  color: #fff !important;\n  text-rendering: optimizeLegibility;\n  font-weight: 700 !important;\n  text-transform: uppercase;\n  letter-spacing: -0.2px;\n  font-size: 14px;\n  margin: 0;\n  line-height: 40px;\n  padding: 30px 0;\n  -webkit-transition: 350ms;\n  -moz-transition: 350ms;\n  -o-transition: 350ms;\n  transition: 350ms;\n}\n\n.navbar-light ul.navbar-nav > li > a {\n  color: #000 !important;\n  font-size: 13px;\n}\n\n/* Dropdown */\n\n.dropdown-submenu {\n  position: relative;\n}\n\n.dropdown-submenu > .dropdown-menu {\n  top: 0;\n  left: 100%;\n  margin-top: -2px;\n  border-radius: 0;\n}\n\n.dropdown-submenu > a:after {\n  display: block;\n  content: \"\\f105\";\n  font-family: \"Font Awesome 5 Free\";\n  float: right;\n  margin-top: 0;\n  margin-right: -5px;\n  border: 0;\n}\n\n.dropdown-submenu:hover > a:after {\n  border-left-color: #fff;\n}\n\n.dropdown-menu {\n  text-align: left;\n  background: #fff;\n  z-index: 100;\n  min-width: 200px;\n  border-radius: 0;\n  border: 0;\n  border-top: 2px solid #ffb600;\n  padding: 0 20px;\n  margin: 0;\n  box-shadow: 0 6px 12px rgba(0, 0, 0, 0.175);\n  @media (min-width: 992px) {\n    box-shadow: 0 6px 12px rgba(0, 0, 0, 0.05);\n  }\n}\n\n.dropdown-menu-large {\n  min-width: 400px;\n}\n\n.dropdown-menu-large > li > ul {\n  padding: 0;\n  margin: 0;\n  list-style: none;\n}\n\n.dropdown-menu-large > li > ul > li > a {\n  padding-left: 0;\n}\n\n.dropdown-menu-large > li > ul > li.active > a {\n  color: #ffb600 !important;\n}\n\n.navbar-nav > li > .dropdown-menu a {\n  background: none;\n}\n\n.dropdown-menu li a {\n  font-family: \"Montserrat\", sans-serif;\n  display: block;\n  font-size: 12px;\n  text-transform: uppercase;\n  font-weight: 700;\n  line-height: normal;\n  text-decoration: none;\n  padding: 15px 0;\n  letter-spacing: 0.3px;\n  border-bottom: 1px solid #e5e5e5;\n  color: #333333;\n  @media (min-width: 992px) {\n    padding: 12px 0;\n  }\n}\n\n.dropdown-menu li:last-child > a {\n  border-bottom: 0;\n}\n\n.dropdown-menu li a:hover,\n.dropdown-menu li a:focus {\n  color: #ffb600;\n}\n\n@media (min-width: 991px) {\n  ul.nav li.dropdown:hover ul.dropdown-menu {\n    display: block;\n  }\n}\n\n@media (min-width: 991px) {\n  ul.nav li.dropdown ul.dropdown-menu li.dropdown-submenu .dropdown-menu {\n    left: 100%;\n    top: 0;\n    display: none;\n  }\n\n  ul.nav li.dropdown ul.dropdown-menu li.dropdown-submenu:hover .dropdown-menu {\n    display: block;\n  }\n}\n\n.dropdown-menu > .active > a,\n.dropdown-menu > .active > a:hover,\n.dropdown-menu > .active > a:focus,\n.dropdown-menu > .active > .dropdown-menu > .active > a {\n  background: none;\n  color: #ffb600;\n}\n\n/*-- Nav Search start --*/\n\n.site-navigation .container,\n.search-area {\n  position: relative;\n}\n\n.search-area {\n  min-height: 70px;\n  padding-right: 0;\n}\n\n.nav-search {\n  position: absolute;\n  cursor: pointer;\n  top: 22px;\n  right: 18px;\n  color: #999;\n  @media (min-width: 992px) {\n    top: 17px;\n  }\n}\n\n.search-block {\n  background-color: rgba(0, 0, 0, 0.65);\n  box-shadow: 0 2px 5px rgba(0, 0, 0, 0.1);\n  display: none;\n  padding: 10px;\n  position: absolute;\n  right: 15px;\n  top: 100%;\n  width: 300px;\n  z-index: 10;\n  margin-top: 0;\n  @media (min-width: 992px) {\n    top: 58px;\n  }\n}\n\n.search-block .form-control {\n  background-color: #222;\n  border: none;\n  color: #fff;\n  width: 100%;\n  height: 40px;\n  padding: 0 12px;\n}\n\n.search-block .search-close {\n  color: #999;\n  position: absolute;\n  top: -53px;\n  right: -4px;\n  font-size: 32px;\n  cursor: pointer;\n  background: #23282d;\n  padding: 5px;\n  @media (min-width: 992px) {\n    top: -46px;\n  }\n}\n\n.search-area .nav-search {\n  top: 23px;\n}\n\n.search-area .search-block .search-close {\n  top: -50px;\n}\n\n.search-area .search-block {\n  right: 0;\n}\n\n/* Get a quote */\n\n.header-get-a-quote .btn-primary {\n  padding: 12px 25px !important;\n  font-size: 13px;\n  border-radius: 3px;\n  line-height: normal;\n  text-transform: capitalize;\n  color: #fff;\n  margin-top: 5px;\n  @media (min-width: 992px) {\n    padding: 12px !important;\n  }\n  @media (min-width: 992px) {\n    padding: 12px 30px !important;\n  }\n}\n\n.header-get-a-quote .btn-primary:hover {\n  background: #272d33;\n  color: #ffb600 !important;\n}\n\nul.navbar-nav > li.header-get-a-quote:hover > a:after {\n  position: relative;\n  content: no-close-quote;\n}\n","/* Table of Content\n==================================================\n1.    Slider\n2.    Call to action\n3.    Features\n4.    Facts\n5.    Services\n6.   Project area\n7.   Content area\n8.   Testimonial\n9.   Subscribe area\n10.   News section\n11.   Footer\n12.   Sub Pages\n13.   Contact Us\n14.   News Listing\n15.   News Single\n16.   Sidebar\n17.   Error page\n*/\n\n/* Slider\n================================================== */\n/*-- Main slide --*/\n.banner-carousel .banner-carousel-item {\n  height: 700px;\n  color: #fff;\n  background-position: 50% 50%;\n  background-size: cover;\n  height: 450px;\n  @media (min-width: 992px) {\n    height: 550px;\n  }\n}\n\n.slider-content {\n  position: relative;\n  height: 100%;\n  width: 100%;\n}\n\n.slide-title-box {\n  font-size: 16px;\n  line-height: 39px;\n  background: #ffb600;\n  color: #fff;\n  display: inline-block;\n  padding: 0 15px;\n  margin: 0 0 10px;\n}\n\n.slide-title {\n  font-size: 30px;\n  line-height: 36px;\n  font-weight: 300;\n  color: #fff;\n  margin: 20px 0 10px;\n  @media (min-width: 992px) {\n    font-size: 22px;\n  }\n  @media (max-width: 992px) {\n    font-size: 16px;\n  }\n}\n\n.slide-sub-title {\n  font-style: normal;\n  font-size: 60px;\n  line-height: 58px;\n  margin: 20px 0;\n  color: #fff;\n  font-weight: 900;\n  text-transform: uppercase;\n  letter-spacing: -1px;\n  @media (min-width: 992px) {\n    font-size: 46px;\n  }\n  @media (max-width: 992px) {\n    font-size: 30px;\n    line-height: 30px;\n  }\n}\n\n.slider-text {\n  display: table;\n  vertical-align: bottom;\n  color: #fff;\n  padding-left: 40%;\n  width: 100%;\n  padding-bottom: 0;\n  padding-top: 20px;\n}\n\n.slider-text .slide-head {\n  font-size: 36px;\n  color: #0052a5;\n  position: relative;\n}\n\n.slider-img {\n  display: block;\n  position: absolute;\n  top: -80px;\n  left: 20%;\n  width: 314px;\n  max-height: 100%;\n}\n\n.slider-img img {\n  display: block;\n  position: relative;\n  max-height: 100%;\n  width: auto;\n}\n\n.slider.btn {\n  margin: 15px 5px 0;\n  border: 2px solid transparent;\n  @media (max-width: 992px) {\n    font-size: 12px;\n  }\n}\n\n.slider.border {\n  background: none;\n  border: 2px solid #ffb600 !important;\n}\n\n.slider.border:hover {\n  background: #ffb600;\n  border: 2px solid transparent;\n}\n\n/* Carousel control */\n.banner-carousel .carousel-control {\n  position: absolute;\n  top: 50%;\n  z-index: 5;\n  display: inline-block;\n  transform: translateY(-50%);\n  background-color: transparent;\n  opacity: 0;\n  filter: alpha(opacity=0);\n  text-shadow: none;\n  transition: all 0.25s ease;\n  padding: 0;\n  outline: 0;\n  border: 0;\n  @media (max-width: 992px) {\n    display: none !important;\n  }\n}\n\n.banner-carousel .slick-dots {\n  opacity: 0;\n  filter: alpha(opacity=0);\n  bottom: 60px;\n}\n.slick-dots {\n  li button::before {\n    font-size: 12px;\n  }\n  li button:hover:before,\n  .slick-dots li button:focus:before,\n  li.slick-active button:before {\n    opacity: 1;\n    color: #ffb600;\n  }\n}\n.slick-slide {\n  outline: 0;\n}\n\n.banner-carousel:hover .carousel-control,\n.banner-carousel:hover .carousel-control,\n.banner-carousel:hover .slick-dots {\n  opacity: 1;\n  filter: alpha(opacity=100);\n}\n\n.banner-carousel .carousel-control.left {\n  left: 20px;\n}\n\n.banner-carousel .carousel-control.right {\n  right: 20px;\n}\n\n.banner-carousel .carousel-control i {\n  background: rgba(0, 0, 0, 0.3);\n  color: #fff;\n  line-height: 58px;\n  width: 60px;\n  height: 60px;\n  font-size: 22px;\n  border-radius: 0;\n  transition: all 500ms ease;\n}\n\n.banner-carousel .carousel-control i:hover {\n  background: #ffb600;\n  color: #fff;\n}\n\n/*-- Animation */\n.banner-carousel [data-animation-in] {\n  opacity: 0;\n}\n\n/* slick Box slider */\n.box-slider-content {\n  top: 50%;\n  padding: 0;\n  position: absolute;\n  width: 100%;\n  transform: translateY(-50%);\n  @media (max-width: 992px) {\n    top: auto;\n    transform: translateY(0);\n    left: 20px;\n    bottom: 20px;\n    width: calc(100% - 40px);\n  }\n}\n\n.box-slider-text {\n  background: #111;\n  background: rgba(0, 0, 0, 0.65);\n  display: inline-block;\n  padding: 20px 30px;\n  max-width: 650px;\n}\n\n.box-slide-title {\n  font-size: 18px;\n  font-weight: 300;\n  margin: 0;\n  color: #fff;\n  @media (max-width: 992px) {\n    font-size: 16px;\n  }\n}\n\n.box-slide-sub-title {\n  font-size: 36px;\n  margin: 8px 0 10px;\n  color: #fff;\n  @media (max-width: 992px) {\n    font-size: 26px;\n  }\n}\n\n.box-slide-description {\n  color: #fff;\n  @media (max-width: 992px) {\n    font-size: 15px;\n  }\n}\n\n.box-slider-text .btn {\n  padding: 10px 20px;\n}\n\n.box-slide.owl-theme .owl-controls {\n  margin: -20px;\n}\n\n/* Call to action\n================================================== */\n\n.call-to-action {\n  background-color: #272d33;\n  padding: 30px;\n}\n\n.call-to-action-title {\n  color: #fff;\n  margin: 0;\n  padding: 25px 0;\n  line-height: normal;\n  font-size: 22px;\n  text-transform: capitalize;\n}\n\n/* Action style box */\n\n.call-to-action-box {\n  margin-top: -50px;\n}\n\n.call-to-action-box .action-style-box {\n  background: #ffb600;\n  padding: 30px;\n}\n\n.action-title {\n  color: #fff;\n  margin: 0;\n  line-height: 36px;\n  font-size: 18px;\n  text-transform: uppercase;\n}\n\n/* Intro\n================================================== */\n\n/* Intro */\n\n.ts-intro {\n  padding-right: 20px;\n}\n\n.into-title {\n  font-weight: 300;\n  text-transform: uppercase;\n  font-size: 18px;\n  line-height: normal;\n  margin: 0;\n}\n\n.into-sub-title {\n  font-weight: 900;\n  text-transform: uppercase;\n  font-size: 32px;\n  line-height: normal;\n  margin: 10px 0;\n}\n\n/*-- Featured Tab --*/\n\n.featured-tab {\n  padding-left: 15px;\n}\n\n.featured-tab .nav-tabs {\n  border: 0;\n}\n\n.featured-tab .nav-tabs > li > a {\n  font-family: \"Roboto Slab\", serif;\n  background: #272d33;\n  color: #fff;\n  text-shadow: none;\n  font-weight: 700;\n  border-radius: 0;\n  text-transform: uppercase;\n  line-height: 50px;\n  margin: 0 1px 20px;\n  padding: 0 20px;\n  border: 0 !important;\n  transition: all 300ms ease;\n}\n\n.featured-tab .tab-content {\n  border-top: 0;\n  padding: 0;\n  overflow: hidden;\n}\n\n.featured-tab .nav.nav-tabs {\n  margin-bottom: 10px;\n}\n\n.featured-tab .nav-tabs > li.active > a {\n  color: #fff;\n  background: #ffb600;\n  position: relative;\n}\n\n.featured-tab .nav-tabs > li.active > a:after {\n  position: absolute;\n  content: \" \";\n  width: auto;\n  height: auto;\n  bottom: -20px;\n  left: 50%;\n  border-width: 10px;\n  border-style: solid;\n  border-color: #ffb600 rgba(0, 0, 0, 0) rgba(0, 0, 0, 0) rgba(0, 0, 0, 0);\n  transform: translateX(-50%);\n}\n\n.featured-tab .lead {\n  font-size: 18px;\n  line-height: 28px;\n  color: #303030;\n  font-weight: 400;\n}\n\n.featured-tab .tab-pane img.pull-left {\n  margin: 0 30px 10px 0;\n}\n\n.featured-tab .tab-pane img.pull-right {\n  margin: 0 0 0 30px;\n}\n\n.featured-tab .tab-icon i {\n  font-size: 230px;\n}\n\n.tab-image-content {\n  padding-left: 0;\n}\n\n.featured-tab .border-title.border-left {\n  display: inline-block;\n  margin-bottom: 25px;\n  font-size: 20px;\n}\n\n/* Tab services */\n\n.featured-tab.tab-services .nav-tabs > li > a {\n  font-size: 14px;\n  padding: 0 21px;\n  text-transform: capitalize;\n}\n\n.featured-tab.tab-services .nav.nav-tabs {\n  margin-bottom: 20px;\n}\n\n/* Facts\n================================================== */\n\n.facts-wrapper {\n  text-align: center;\n}\n\n.facts-wrapper .ts-facts {\n  color: #fff;\n}\n\n.ts-facts .ts-facts-icon i {\n  font-size: 42px;\n  color: #ffb600;\n}\n\n.ts-facts .ts-facts-content .ts-facts-num {\n  color: #fff;\n  font-size: 44px;\n  margin: 30px 0 20px;\n}\n\n.ts-facts .ts-facts-content .ts-facts-title {\n  font-size: 16px;\n  color: #ffb600;\n  margin: 0;\n}\n\n/* Services\n================================================== */\n\n/* Service box */\n\n.ts-service-box .ts-service-icon i {\n  font-size: 36px;\n  float: left;\n  color: #ffb600;\n}\n\n.ts-service-box .ts-service-box-content {\n  margin-left: 62px;\n  margin-bottom: 30px;\n}\n\n.tab-content .ts-service-box .ts-service-box-content {\n  margin-left: 90px;\n}\n\n.ts-service-box .ts-service-box-content h3 {\n  font-size: 16px;\n  margin-bottom: 10px;\n  line-height: 28px;\n}\n\n.ts-service-box .ts-service-box-info {\n  margin-left: 25px;\n  margin-bottom: 40px;\n}\n\n.service-box-title {\n  font-size: 16px;\n  margin: 0 0 10px;\n  a {\n    color: #333;\n    &:hover {\n      color: #ffb600;\n    }\n  }\n}\n\n/* Service box bg */\n.ts-service-box-bg {\n  background: #252525;\n  color: #fff;\n  padding: 30px;\n}\n\n.ts-service-box-bg h4,\n.ts-service-box-bg h3 {\n  color: #fff;\n}\n\n/* Service box \n\n.ts-service-box .ts-service-icon i {\n  font-size: 24px;\n  float: left;\n  color: #fff;\n  background: #ffb600;\n  border-radius: 100%;\n  width: 60px;\n  height: 60px;\n  line-height: 60px;\n  text-align: center;\n}\n\n.ts-service-box .ts-service-box-content {\n  margin-left: 80px;\n  margin-bottom: 30px;\n}\n\n.tab-content .ts-service-box .ts-service-box-content {\n  margin-left: 90px;\n}\n\n.ts-service-box .ts-service-box-content h3 {\n  font-size: 18px;\n  margin-bottom: 15px;\n}\n\n.ts-service-box .ts-service-box-info {\n  margin-left: 90px;\n  margin-bottom: 40px;\n}\n\n.service-box-title {\n  font-size: 18px;\n  margin: 0 0 10px;\n}\n\n.service-box-title a {\n  color: #333;\n}\n\n.service-box-title a:hover {\n  color: #ffb600;\n}\n\n.service-center-img {\n  padding: 0 20px;\n}\n*/\n\n/* Icon squre */\n.ts-service-icon.icon-round i {\n  font-size: 24px;\n  color: #fff;\n  background: #ffb600;\n  text-align: center;\n  border-radius: 100%;\n  width: 60px;\n  height: 60px;\n  line-height: 60px;\n  margin-bottom: 20px;\n  position: relative;\n  float: none;\n}\n\n/* Icon left */\n\n.ts-service-box.icon-left .ts-service-box-icon {\n  float: left;\n}\n\n.ts-service-box.icon-left .ts-service-box-icon i {\n  background: #ffb600;\n  color: #fff;\n}\n\n.ts-service-box.icon-left .ts-service-box-info {\n  margin-left: 90px;\n}\n\n.ts-service-box.icon-left .ts-service-box-info h3 {\n  margin-top: 0;\n  margin-bottom: 5px;\n}\n\n/* Service no box */\n\n.service-no {\n  font-size: 48px;\n  color: #dbdbdb;\n  float: left;\n  margin-top: 10px;\n}\n\n.ts-service-box-content .ts-service-box-info {\n  margin-left: 90px;\n}\n\n/* Service Image */\n.ts-service-image-wrapper {\n  margin-bottom: 30px;\n}\n\n.ts-service-icon i {\n  font-size: 28px;\n  margin-right: 15px;\n  margin-top: 2px;\n}\n\n.ts-service-info {\n  margin-left: 30px;\n  h3 {\n    font-size: 16px;\n  }\n  .learn-more {\n    text-transform: uppercase;\n    font-size: 14px;\n    font-weight: 600;\n    &:hover {\n      color: #ffb600;\n    }\n  }\n}\n\n/* Service Classic */\n\n.ts-service-classic .ts-service-icon i {\n  font-size: 24px;\n  float: left;\n  color: #fff;\n  background: #ffb600;\n  border-radius: 100%;\n  width: 60px;\n  height: 60px;\n  line-height: 60px;\n  text-align: center;\n  transition: all 0.3s;\n}\n\n.ts-service-classic .ts-service-box-info {\n  margin-left: 80px;\n}\n\n.ts-service-classic:hover .ts-service-icon i {\n  background: #ffb600;\n}\n\n/* Projects area\n================================================== */\n\n/* Project filter nav */\n.shuffle-btn-group {\n  display: inline-block;\n  margin: 20px 0 50px;\n  width: 100%;\n  border-bottom: 3px solid #ffb600;\n  label {\n    display: inline-block;\n    color: #212121;\n    font-size: 14px;\n    padding: 6px 25px;\n    padding-top: 10px;\n    font-weight: 700;\n    text-transform: uppercase;\n    transition: all 0.3s;\n    cursor: pointer;\n    margin: 0;\n    &.active {\n      color: #212121;\n      background: #ffb600;\n    }\n\n    input {\n      display: none;\n    }\n  }\n}\n\n/* Project shuffle Item */\n.shuffle-item {\n  padding: 0;\n\n  .project-img-container {\n    position: relative;\n    overflow: hidden;\n    img {\n      transform: perspective(1px) scale3d(1.1, 1.1, 1);\n      transition: all 400ms;\n    }\n    &:hover img {\n      transform: perspective(1px) scale3d(1.15, 1.15, 1);\n    }\n    &:after {\n      opacity: 0;\n      position: absolute;\n      content: \"\";\n      top: 0;\n      right: auto;\n      left: 0;\n      width: 100%;\n      height: 100%;\n      background-color: rgba(0, 0, 0, 0.7);\n      transition: all 400ms;\n    }\n    &:hover:after {\n      opacity: 1;\n    }\n\n    .gallery-popup .gallery-icon {\n      position: absolute;\n      top: 0;\n      right: 0;\n      z-index: 1;\n      padding: 5px 12px;\n      background: #ffb600;\n      color: #fff;\n      opacity: 0;\n      transform: perspective(1px) scale3d(0, 0, 0);\n      transition: all 400ms;\n    }\n    &:hover .gallery-popup .gallery-icon {\n      opacity: 1;\n      transform: perspective(1px) scale3d(1, 1, 1);\n    }\n\n    .project-item-info {\n      position: absolute;\n      top: 50%;\n      margin-top: -10%;\n      bottom: 0;\n      left: 0;\n      right: 0;\n      padding: 0 30px;\n      z-index: 1;\n    }\n    .project-item-info-content {\n      opacity: 0;\n      transform: perspective(1px) translate3d(0, 15px, 0);\n      transition: all 400ms;\n\n      .project-item-title {\n        font-size: 20px;\n        a {\n          color: #fff;\n          &:hover {\n            color: #ffb600;\n          }\n        }\n      }\n      .project-cat {\n        background: #ffb600;\n        display: inline-block;\n        padding: 2px 8px;\n        font-weight: 700;\n        color: #000;\n        font-size: 10px;\n        text-transform: uppercase;\n      }\n    }\n    &:hover .project-item-info-content {\n      opacity: 1;\n      transform: perspective(1px) translate3d(0, 0, 0);\n    }\n  }\n}\n\n.general-btn .btn-primary:hover {\n  background: #000;\n}\n\n/* Project owl */\n\n.owl-theme.project-slide {\n  margin-top: 60px;\n}\n\n.project-slide .item {\n  position: relative;\n  overflow: hidden;\n  width: 100%;\n}\n\n.project-item img {\n  width: 100%;\n  max-width: auto;\n  transition: all 0.6s ease 0s;\n}\n\n.project-item:hover img {\n  transform: scale(1.1, 1.1);\n}\n\n.project-item-content {\n  position: absolute;\n  bottom: -1px;\n  padding: 15px 20px;\n  width: 100%;\n  background: #ffb600;\n}\n\n.owl-theme.project-slide .owl-nav > div {\n  position: absolute;\n  top: -70px;\n  right: 0;\n  transform: translateY(-50%);\n}\n\n.project-slide .owl-nav > div {\n  display: inline-block;\n  margin: 0 2px;\n  font-size: 20px;\n  background: #ffb600;\n  color: #fff;\n  width: 30px;\n  height: 30px;\n  line-height: 30px;\n  text-align: center;\n}\n\n.owl-theme.project-slide .owl-nav > .owl-prev {\n  right: 35px;\n  left: auto;\n}\n\n/* Projects Single page */\n\n.project-title {\n  font-size: 30px;\n}\n\n.project-info-label {\n  color: #303030;\n  font-weight: 700;\n  font-size: 14px;\n}\n\n.project-info-content {\n  font-size: 12px;\n}\n\n.project-info li {\n  margin-bottom: 5px;\n}\n\n.project-link {\n  margin-top: 15px;\n}\n\n/* Content area\n================================================== */\n\n/* Accordion */\n.accordion-group {\n  .card {\n    border-radius: 0;\n    margin-bottom: 10px;\n    border-bottom: 1px solid #dfdfdf !important;\n  }\n  .card-body {\n    padding: 15px 20px;\n    img {\n      max-width: 100px;\n      margin-bottom: 10px;\n    }\n  }\n  .card-header .btn {\n    font-size: 16px;\n    text-transform: uppercase;\n    font-weight: 700;\n    padding: 13px 15px;\n    padding-bottom: 10px;\n\n    &:before {\n      font-family: \"Font Awesome 5 Free\";\n      position: absolute;\n      z-index: 0;\n      font-size: 14px;\n      right: 16px;\n      padding: 3px 8px 1px;\n      text-align: center;\n      border-radius: 3px;\n      top: 12px;\n      content: \"\\f107\";\n      font-weight: 700;\n      background-color: #333;\n      color: #fff;\n      transition: 0.3s;\n    }\n\n    &[aria-expanded=\"true\"] {\n      color: #ffb600;\n      &::before {\n        content: \"\\f106\";\n        background-color: #ffb600;\n      }\n    }\n  }\n  &.accordion-classic {\n    .card-header .btn:before {\n      display: none;\n    }\n  }\n}\n\n/* Clients */\n.clients-logo {\n  margin: 0 0 30px;\n  border: 1px solid #dadada;\n  min-height: 105px;\n  padding: 0 30px;\n  display: flex;\n  flex-direction: column;\n  justify-content: center;\n  align-items: center;\n  align-content: center;\n}\n\n.clients-logo img {\n  filter: grayscale(100%);\n  filter: gray;\n}\n\n/* Testimonial\n================================================== */\n.testimonial-area {\n  padding: 100px 0;\n  background-color: #ffb600;\n  background-image: url(../images/parallax2.jpg);\n  background-repeat: no-repeat;\n  background-size: cover;\n  background-attachment: fixed;\n  background-position: 50% 50%;\n}\n\n.testimonial-area .border-title,\n.testimonial-area .border-sub-title {\n  color: #fff;\n}\n\n.quote-item .quote-text {\n  margin: 0 0 10px;\n  display: inline-block;\n  padding: 0 40px 30px 60px;\n  background-color: #fff;\n  position: relative;\n  font-size: 16px;\n  font-style: italic;\n  @media (max-width: 992px) {\n    padding: 0 40px 30px 50px;\n  }\n}\n\n.quote-item .quote-text:before {\n  content: \"\\f10d\";\n  font-family: \"Font Awesome 5 Free\";\n  position: absolute;\n  font-size: 30px;\n  left: 0;\n  top: 0;\n  font-weight: 700;\n  color: #ffc009;\n}\n\n.testimonial-slide .slick-dots {\n  bottom: -35px;\n}\n\nimg.testimonial-thumb {\n  max-width: 80px;\n  float: left;\n  margin-right: 20px;\n  border-radius: 5px;\n}\n\n.quote-item-info {\n  padding-top: 15px;\n  display: inline-block;\n}\n\n.quote-author {\n  font-size: 16px;\n  line-height: 18px;\n  margin: 0 0 2px;\n  font-weight: 700;\n  display: block;\n  color: #ffb600;\n}\n\n.quote-item-footer {\n  margin-top: 0;\n  margin-left: 60px;\n  @media (max-width: 992px) {\n    margin-left: 0;\n  }\n}\n\n/* Testimonial Border */\n\n.quote-item.quote-border .quote-text-border {\n  border: 1px solid #ffb600;\n  padding: 20px;\n  position: relative;\n  line-height: 28px;\n  color: #666;\n  font-size: 18px;\n  text-align: center;\n}\n\n.quote-item.quote-border .quote-text-border:before {\n  border: 12px solid;\n  border-color: #e1e1e1 transparent transparent;\n  border-top-color: #ffb600;\n  bottom: -24px;\n  position: absolute;\n  content: \"\";\n  display: block;\n  height: 0;\n  width: 0;\n  left: 0;\n  margin: 0 auto;\n  right: 0;\n}\n\n.quote-item.quote-border .quote-text-border:after {\n  border: 12px solid;\n  border-color: #fff transparent transparent;\n  bottom: -22px;\n  position: absolute;\n  content: \"\";\n  display: block;\n  height: 0;\n  width: 0;\n  left: 0;\n  margin: 0 auto;\n  right: 0;\n}\n\n.quote-item.quote-border .quote-item-footer {\n  margin-left: 0;\n  text-align: center;\n  margin-top: 35px;\n}\n\n.quote-item.quote-border .quote-item-footer img.testimonial-thumb {\n  float: none;\n  margin: 0;\n}\n\n.quote-item.quote-border .quote-item-footer .quote-item-info {\n  display: block;\n}\n\n/* Subscribe area\n================================================== */\n\n.subscribe {\n  background: #ffb600;\n  padding: 0;\n}\n\n/* Call to action */\n\n.subscribe-call-to-acton {\n  min-height: 115px;\n  padding: 30px 0 0 30px;\n  @media (max-width: 992px) {\n    text-align: center;\n    padding: 30px 0;\n    min-height: auto;\n  }\n}\n\n.subscribe-call-to-acton h3 {\n  font-size: 18px;\n  margin-top: 0;\n  margin-bottom: 5px;\n}\n\n.subscribe-call-to-acton h4 {\n  color: #fff;\n  font-size: 24px;\n  margin: 0;\n}\n\n/* Newsletter */\n\n.ts-newsletter {\n  background: #252525;\n  position: relative;\n  min-height: 115px;\n  padding: 15px 0 0 50px;\n  @media (max-width: 992px) {\n    padding-top: 20px;\n    padding-bottom: 10px;\n  }\n  @media (max-width: 992px) {\n    padding: 30px 5px 15px 5px;\n    min-height: auto;\n    text-align: center;\n  }\n  &:after {\n    content: \"\";\n    position: absolute;\n    background: #252525;\n    display: block;\n    width: 100%;\n    height: 100%;\n    right: -100%;\n    top: 0;\n  }\n}\n.newsletter-form input {\n  background: none;\n  font-size: 12px;\n  height: 45px;\n  border: 1px solid rgba(255, 255, 255, 0.3);\n}\n\n/* News section\n================================================== */\n\n.latest-post {\n  position: relative;\n}\n\n.latest-post .image-angle:before {\n  border-bottom: 20px solid #f9f9f9;\n}\n\n.latest-post .post-title {\n  font-size: 16px;\n  line-height: 24px;\n  margin: 0;\n  font-weight: 600;\n}\n\n.latest-post .post-title a {\n  color: #303030;\n}\n\n.latest-post .post-title a:hover {\n  color: #ffb600;\n}\n\n.latest-post-meta {\n  font-size: 13px;\n  text-transform: uppercase;\n}\n\n.latest-post .post-body {\n  padding: 20px 0 5px;\n}\n\n/* Footer\n================================================== */\n\n/*- Footer common */\n\n.footer {\n  background-color: #0d0d0d;\n  color: #999;\n}\n\n.footer-main {\n  padding: 80px 0 60px;\n}\n\n.footer .widget-title {\n  font-size: 16px;\n  font-weight: 700;\n  position: relative;\n  margin: 0 0 30px;\n  padding-left: 15px;\n  text-transform: uppercase;\n  color: #fff;\n  border-left: 3px solid #ffb600;\n}\n\n/* Footer about us */\n\n.footer-logo {\n  margin-bottom: 25px;\n}\n\n/* Footer social */\n\n.footer-social {\n  margin-top: 15px;\n}\n\n.footer-social .widget-title {\n  font-size: 14px;\n  margin-bottom: 10px;\n}\n\n.footer-social ul {\n  list-style: none;\n  margin: 0;\n  padding: 0;\n  margin-left: -13px;\n  li {\n    display: inline-block;\n    a i {\n      display: block;\n      font-size: 16px;\n      color: #999;\n      transition: 400ms;\n      padding: 10px 13px;\n    }\n    &:hover {\n      color: #fff;\n    }\n  }\n}\n\n/* Links */\n\n.footer-widget ul.list-arrow li {\n  border-bottom: 1px solid rgba(255, 255, 255, 0.07);\n  padding: 8px 0;\n}\n\n.footer-widget ul.list-arrow li:last-child {\n  border-bottom: 0;\n}\n\n.footer-widget ul.list-arrow li a,\n.footer-widget ul.list-arrow li:before {\n  color: #747474;\n}\n\n.footer-widget ul.list-arrow li:hover a,\n.footer-widget ul.list-arrow li:hover {\n  color: #ffb600;\n}\n\n.working-hours {\n  padding-right: 10px;\n}\n\n.working-hours .text-right {\n  float: right;\n}\n\n/*-- Copyright --*/\n\n.copyright {\n  background: #ffb600;\n  color: #111;\n  padding: 25px 0;\n  position: relative;\n  z-index: 1;\n  font-weight: 600;\n  font-size: 12px;\n}\n\n.footer-menu ul li {\n  display: inline-block;\n  line-height: 12px;\n  padding-left: 15px;\n}\n\n.footer-menu ul.nav li a {\n  background: none;\n  color: #111;\n  padding: 0;\n}\n\n.footer-menu ul li a:hover {\n  color: #fff;\n}\n\n#back-to-top {\n  right: 40px;\n  top: auto;\n  z-index: 10;\n  display: none;\n  .btn:focus {\n    outline: 0;\n    box-shadow: none;\n  }\n  @media (max-width: 992px) {\n    right: 15px;\n  }\n}\n\n#back-to-top.position-fixed {\n  bottom: 20px;\n}\n\n#back-to-top .btn.btn-primary {\n  width: 36px;\n  height: 36px;\n  line-height: 36px;\n  background: rgba(0, 0, 0, 0.9);\n  border-radius: 3px;\n  color: #ffb600;\n  font-weight: 700;\n  font-size: 16px;\n  padding: 0;\n  @media (max-width: 992px) {\n    width: 32px;\n    height: 32px;\n    line-height: 32px;\n    font-size: 14px;\n  }\n}\n\n#back-to-top .btn.btn-primary:hover {\n  color: #fff;\n}\n\n/* Sub Pages\n================================================== */\n\n/*-- Title border --*/\n\n.main-container .border-left {\n  margin-bottom: 30px;\n}\n\n/*-- Banner --*/\n\n.banner-area {\n  position: relative;\n  min-height: 300px;\n  color: #fff;\n  background-position: 50% 50%;\n  background-size: cover;\n}\n\n.banner-title {\n  color: #fff;\n  text-transform: uppercase;\n  font-size: 58px;\n  font-weight: 900;\n  @media (max-width: 992px) {\n    font-size: 48px;\n  }\n  @media (max-width: 992px) {\n    font-size: 32px;\n  }\n}\n\n.banner-text {\n  position: absolute;\n  top: 50%;\n  left: 0;\n  right: 0;\n  max-width: 1170px;\n  margin: 0 auto;\n  width: 100%;\n  z-index: 1;\n  transform: translateY(-50%);\n}\n\n.banner-heading {\n  text-align: center;\n}\n\n.breadcrumb {\n  padding: 0;\n  background: none;\n  font-weight: 700;\n  text-transform: uppercase;\n  font-size: 12px;\n  li a,\n  .breadcrumb-item,\n  li a:focus,\n  li a:hover {\n    color: #fff !important;\n  }\n  .breadcrumb-item + .breadcrumb-item::before {\n    color: #fff;\n  }\n}\n\n/*-- About us page --*/\n\n/* Slider pages */\n.page-slider {\n  .carousel-control {\n    position: absolute;\n    top: 50%;\n    z-index: 5;\n    display: inline-block;\n    transform: translateY(-50%);\n    background-color: transparent;\n    text-shadow: none;\n    transition: all 0.25s ease;\n    padding: 0;\n    outline: 0;\n    border: 0;\n  }\n\n  .carousel-control.left {\n    left: 0;\n  }\n  .carousel-control.right {\n    right: 0;\n  }\n  .carousel-control i {\n    background: rgba(0, 0, 0, 0.3);\n    color: #fff;\n    line-height: 70px;\n    width: 40px;\n    height: 70px;\n    font-size: 22px;\n    border-radius: 0;\n    transition: all 500ms ease;\n  }\n  .carousel-control i:hover {\n    background: #ffb600;\n    color: #fff;\n  }\n}\n.page-slider.small-bg .item {\n  min-height: 330px;\n  background-size: cover;\n}\n\n.page-slider.small-bg .box-slider-content {\n  left: 20%;\n}\n\n.page-slider.small-bg .box-slider-text {\n  background: rgba(0, 0, 0, 0.55);\n  padding: 5px 20px;\n}\n\n.page-slider.small-bg .box-slide-title {\n  font-size: 28px;\n  color: #fff;\n  font-weight: 900;\n}\n\n/*-- Get a quote page --*/\n\n.page-quote-form {\n  background: #f2f2f2;\n  padding: 30px 50px 50px;\n}\n\n.get-a-quote-img {\n  margin-bottom: -190px;\n}\n\n/*-- Partners carousel --*/\n\n.partner-logo {\n  border: 1px solid #eee;\n  padding: 20px;\n  margin-top: 40px;\n  margin-bottom: 10px;\n}\n\n.partner-logo img {\n  transition: 350ms;\n  opacity: 0.6;\n  filter: grayscale(100%);\n}\n\n.partner-logo:hover img {\n  opacity: 1;\n  filter: grayscale(0%);\n}\n\n#partners-carousel .partner-logo {\n  border: 0;\n  border-right: 1px solid #eee;\n  padding: 0 15px;\n  margin-top: 20px;\n}\n\n#partners-carousel .partner-logo.last {\n  border-right: 0;\n}\n\n/*-- Team page --*/\n.team-slide {\n  .slick-slide {\n    margin-left: 25px;\n    padding-bottom: 60px;\n  }\n  .slick-list {\n    margin-left: -25px;\n  }\n  .carousel-control {\n    position: absolute;\n    bottom: 0;\n    left: 50%;\n    border: 0;\n    background-color: #ddd;\n    height: 37px;\n    width: 37px;\n    border-radius: 4px;\n    transition: 0.3s;\n    z-index: 6;\n    &:hover {\n      background-color: #ffb600;\n      color: #fff;\n    }\n    &.left {\n      transform: translateX(calc(-50% - 25px));\n    }\n    &.right {\n      transform: translateX(calc(-50% + 25px));\n    }\n    &.slick-disabled {\n      opacity: 0.4;\n      &:hover {\n        background-color: #ddd;\n        color: #000;\n      }\n    }\n  }\n}\n.ts-team-wrapper {\n  position: relative;\n  overflow: hidden;\n  .ts-team-content {\n    position: absolute;\n    top: 76%;\n    left: 0;\n    width: 100%;\n    height: 100%;\n    padding: 15px 25px;\n    margin-top: 0;\n    color: #fff;\n    background: rgba(0, 0, 0, 0.5);\n    transition: 350ms;\n    @media (min-width: 992px) {\n      top: 72%;\n    }\n    @media (max-width: 992px) {\n      text-align: center;\n    }\n  }\n  .ts-name {\n    font-size: 16px;\n    margin-top: 0;\n    margin-bottom: 3px;\n    line-height: normal;\n    color: #ffb600;\n  }\n  .ts-designation {\n    color: #fff;\n    font-size: 14px;\n    margin-bottom: 15px;\n    font-weight: 700;\n  }\n  .team-social-icons {\n    a i {\n      color: #fff;\n      margin-right: 8px;\n      text-align: center;\n      transition: 400ms;\n      &:hover {\n        color: #ffb600;\n      }\n    }\n  }\n  &:hover .ts-team-content {\n    top: 0;\n    padding-top: 50px;\n  }\n}\n\n/* Team Classic */\n.ts-team-content-classic {\n  margin-top: 15px;\n  .ts-name {\n    font-size: 16px;\n    margin-bottom: 5px;\n    color: #212121;\n  }\n  .ts-designation {\n    color: #888;\n    margin-bottom: 5px;\n    font-weight: 600;\n  }\n  .team-social-icons a i {\n    color: #999;\n  }\n  .team-social-icons a i:hover {\n    color: #ffb600;\n  }\n}\n\n/*-- Pricing table  --*/\n.ts-pricing-box {\n  margin: 20px 0;\n  padding: 0;\n  text-align: center;\n  background: #f9f9f9;\n  .ts-pricing-header {\n    background: #252525;\n    color: #fff;\n    position: relative;\n    padding: 30px 20px;\n  }\n  .ts-pricing-name {\n    font-size: 18px;\n    line-height: normal;\n    margin: 0 0 5px 0;\n    color: #fff;\n  }\n  .ts-pricing-price {\n    font-size: 44px;\n    color: #fff;\n    margin: 15px 0 0;\n    display: inline-block;\n    > small {\n      font-size: 16px;\n      line-height: 16px;\n      display: block;\n      margin-top: 15px;\n      color: #fff;\n    }\n  }\n  .ts-pricing-features {\n    padding: 15px 0;\n    ul {\n      padding: 0 20px;\n      > li {\n        padding: 20px 0;\n        border-top: 1px dotted #e5e5e5;\n        &:first-child {\n          border-top: 0;\n        }\n      }\n    }\n  }\n  .plan-action {\n    padding-bottom: 40px;\n  }\n}\n/* Pricing featured */\n.ts-pricing-box.ts-pricing-featured .ts-pricing-header {\n  background: #ffb600;\n}\n\n/* Contact Us\n================================================== */\n\n.map {\n  height: 450px;\n  z-index: 1;\n}\n\n.contact-info-box {\n  margin-top: 20px;\n}\n\n.contact-info-box i {\n  float: left;\n  font-size: 24px;\n  color: #ffb600;\n}\n\n.contact-info-box-content {\n  padding-left: 40px;\n}\n\n.contact-info-box-content h4 {\n  font-size: 16px;\n  margin-top: 0;\n  line-height: normal;\n  font-weight: 700;\n}\n\n.contact-info-box-content p {\n  margin-bottom: 0;\n}\n\nlabel {\n  font-weight: 400;\n}\n\n/* Contact page 2 */\n\n.ts-service-box.text-center .ts-service-icon.icon-squre i {\n  float: none;\n  margin-bottom: 20px;\n}\n\n.ts-service-box.text-center .ts-service-box-content {\n  margin: 0;\n}\n\n/* News Listing\n================================================== */\n\n.post {\n  border-bottom: 1px solid #dadada;\n  padding: 0 0 30px;\n  margin: 0 0 45px;\n}\n\n.post.last {\n  padding-bottom: 0;\n  margin-bottom: 0;\n  border-bottom: 0;\n}\n\n.post-body {\n  padding: 20px 0;\n}\n\n.entry-header .entry-title {\n  font-size: 24px;\n  margin: 5px 0 15px;\n  position: relative;\n  line-height: 34px;\n  text-transform: capitalize;\n}\n\n.entry-header .entry-title a {\n  color: #303030;\n}\n\n.entry-header .entry-title a:hover {\n  color: #ffb600;\n}\n\n.post-single .entry-header .entry-title {\n  font-size: 28px;\n}\n\n/* Meta */\n\n.post-meta {\n  padding-bottom: 10px;\n}\n\n.post-meta a {\n  color: #303030;\n}\n\n.post-meta a:hover {\n  color: #ffb600;\n}\n\n.post-meta span {\n  margin-right: 10px;\n  padding-right: 10px;\n  border-right: 1px solid #dadada;\n  line-height: 12px;\n  display: inline-block;\n}\n\n.post-meta i {\n  color: #bbb;\n  margin-right: 3px;\n}\n\n.post-meta .post-comment {\n  border-right: 0;\n}\n\n.post-meta .post-comment .comments-link {\n  margin-left: 5px;\n}\n\n.post-footer .btn.btn-primary {\n  font-size: 12px;\n  margin-top: 10px;\n}\n\n/* Pagination */\n\n.paging {\n  margin-bottom: -5px;\n}\n\n.pagination li a {\n  border-radius: 0 !important;\n  margin-right: 8px;\n  color: #7c7c7c;\n}\n\n.pagination > .active > a,\n.pagination > .active > a:hover,\n.pagination > li > a:hover {\n  color: #fff;\n  background: #ffb600;\n  border: 1px solid transparent;\n}\n\n/* News Single\n================================================== */\n\n.tags-area {\n  margin: 20px 0;\n}\n\n.post-tags a {\n  border: 1px solid #dadada;\n  color: #7c7c7c;\n  display: inline-block;\n  font-size: 12px;\n  padding: 3px 10px;\n  margin-left: 3px;\n}\n\n.post-tags a:hover {\n  background: #ffb600;\n  color: #fff;\n  border: 1px solid transparent;\n}\n\n/* Post social */\n\n.post-social-icons > li {\n  display: inline-block;\n}\n\n.post-social-icons a i {\n  margin-left: 5px;\n  font-size: 12px;\n  width: 28px;\n  height: 26px;\n  line-height: 26px;\n  color: #fff;\n  text-align: center;\n}\n\n.post-social-icons a i.fa-facebook-f {\n  background: #41578a;\n}\n\n.post-social-icons a i.fa-twitter {\n  background: #64bae2;\n}\n\n.post-social-icons a i.fa-google-plus {\n  background: #c0343d;\n}\n\n.post-social-icons a i.fa-linkedin {\n  background: #3397b6;\n}\n\n/* Author box */\n\n.author-box {\n  border: 1px solid #dadada;\n  padding: 20px 20px 15px;\n  margin: 20px 0;\n}\n\n.author-img img {\n  width: 110px;\n  height: 110px;\n  margin-right: 30px;\n}\n\n.author-info h3 {\n  margin-top: 0;\n  margin-bottom: 5px;\n  font-size: 18px;\n  font-weight: 600;\n}\n\n.author-info h3 span {\n  font-size: 12px;\n  color: #999;\n  border-left: 1px solid #afafaf;\n  padding-left: 10px;\n  margin-left: 10px;\n  font-weight: 500;\n}\n\n/* Comments area */\n\n.comments-area {\n  margin: 40px 0;\n}\n\n.comments-list .comment-content {\n  margin: 15px 0;\n}\n\n.comments-list .comment-reply {\n  color: #303030;\n  font-weight: 400;\n}\n\n.comments-list .comment-reply:hover {\n  color: #ffb600;\n}\n\n.comments-counter {\n  font-size: 18px;\n}\n\n.comments-counter a {\n  color: #323232;\n}\n\n.comments-list {\n  list-style: none;\n  margin: 0;\n  padding: 20px 0;\n}\n\n.comments-list .comment {\n  border-bottom: 1px solid #e7e7e7;\n  padding-bottom: 20px;\n  margin-bottom: 30px;\n}\n\n.comments-list .comment.last {\n  border-bottom: 0;\n  padding-bottom: 0;\n  margin-bottom: 0;\n}\n\n.comments-list img.comment-avatar {\n  width: 84px;\n  height: 84px;\n  margin-right: 30px;\n  @media (max-width: 992px) {\n    width: 40px;\n    height: 40px;\n    margin-right: 25px;\n  }\n}\n\n.comments-list .comment-author {\n  margin-bottom: 0;\n  margin-top: 0;\n  font-weight: 600;\n  font-size: 16px;\n  color: #303030;\n}\n\n.comments-list .comment-date {\n  color: #959595;\n  margin-bottom: 5px;\n  font-size: 12px;\n  @media (max-width: 992px) {\n    float: none !important;\n    display: inline-block;\n  }\n}\n\n.comments-reply {\n  list-style: none;\n  margin: 0 0 0 70px;\n  @media (max-width: 992px) {\n    margin: 0;\n    padding: 0;\n  }\n}\n\n.comments-form {\n  margin-bottom: 0;\n}\n\n.comments-form .title-normal {\n  margin-bottom: 20px;\n}\n\n.comments-form .btn.btn-primary {\n  margin-top: 20px;\n}\n\n/* Sidebar\n================================================== */\n\n.sidebar .widget-title {\n  font-size: 16px;\n  font-weight: 700;\n  position: relative;\n  margin: 0 0 30px;\n  padding-left: 15px;\n  text-transform: uppercase;\n  border-left: 3px solid #ffb600;\n}\n\n/* Widget common */\n\n.sidebar .widget {\n  margin-bottom: 40px;\n}\n\n.sidebar-left .widget {\n  margin-right: 20px;\n}\n\n.sidebar-right .widget {\n  margin-left: 20px;\n}\n\n.sidebar .widget.box {\n  padding: 25px;\n}\n\n.widget.box.solid {\n  background: #f2f2f2;\n}\n\n.widget.box.red {\n  background: #ec483b;\n  color: #fff;\n}\n\n.widget.box.red .widget-title {\n  color: #fff;\n}\n\n.widget ul li {\n  line-height: 30px;\n}\n\n.sidebar .widget ul li a {\n  color: #303030;\n}\n\n.sidebar .widget ul li a:hover {\n  color: #ffb600;\n}\n\n.sidebar .widget ul li i {\n  margin-right: 5px;\n}\n\n.sidebar .btn {\n  font-weight: 700;\n  font-size: 12px;\n  margin-top: 15px;\n  padding: 10px 25px;\n}\n\n/* Sidebar nav */\n\n.sidebar ul.nav-tabs {\n  border: 0;\n}\n\n.sidebar ul.nav-tabs li {\n  width: 100%;\n  a {\n    color: #303030;\n    border-radius: 0;\n    padding: 15px 0;\n    padding-left: 0;\n    font-weight: 400;\n    border-bottom: 1px solid #ddd;\n    display: block;\n    transition: 400ms;\n  }\n}\n\n.sidebar ul.nav-tabs li.active a,\n.sidebar ul.nav-tabs li:hover a {\n  color: #ffb600;\n}\n\n.sidebar ul.nav-tabs li {\n  color: #303030;\n  line-height: normal;\n}\n\n.sidebar ul.nav-tabs li:last-child a {\n  border-bottom: 0;\n}\n\n/* Service menu */\n\n.sidebar ul.service-menu {\n  li {\n    width: 100%;\n    a {\n      background-color: #f4f4f4;\n      padding: 15px 20px;\n      border: 0;\n      margin-bottom: 8px;\n      position: relative;\n      transition: 400ms;\n      display: block;\n    }\n    &.active a,\n    &:hover a {\n      background: #ffb600;\n      color: #fff;\n      cursor: pointer;\n    }\n  }\n}\n\n/* Recent News */\n.widget.recent-posts .widget-title {\n  margin-bottom: 35px;\n}\n\n.widget.recent-posts {\n  ul li {\n    border-bottom: 1px solid #dadada;\n    padding-bottom: 15px;\n    margin-bottom: 17px;\n    &:last-child {\n      border: 0;\n      padding-bottom: 0;\n      margin-bottom: 0;\n    }\n  }\n  .posts-thumb img {\n    margin-right: 15px;\n    width: 90px;\n    height: 70px;\n  }\n  .post-info .entry-title {\n    font-size: 13px;\n    font-weight: 600;\n    line-height: 20px;\n    margin: 0;\n    a {\n      color: #303030;\n      display: inline-block;\n      &:hover {\n        color: #ffb600;\n      }\n    }\n  }\n  .post-date {\n    font-weight: 400;\n    color: #999;\n    text-transform: capitalize;\n  }\n}\n\n/* Widget tags */\n.widget-tags ul > li {\n  float: left;\n  margin: 3px;\n}\n\n.sidebar .widget-tags ul > li a {\n  border: 1px solid #dadada;\n  color: #303030;\n  display: block;\n  font-size: 14px;\n  padding: 3px 15px;\n  transition: all 0.3s ease 0s;\n}\n\n.sidebar .widget-tags ul > li a:hover {\n  background: #ffb600;\n  color: #fff;\n  border: 1px solid transparent;\n}\n\n/* Error page\n================================================== */\n\n.error-page .error-code h2 {\n  display: block;\n  font-size: 200px;\n  line-height: 200px;\n  color: #303030;\n  margin-bottom: 20px;\n}\n\n.error-page .error-body .btn {\n  margin-top: 30px;\n  font-weight: 700;\n}\n"]}